import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export default class IntroScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public game!: Phaser.Game;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private bgs: Phaser.GameObjects.Image[] = [];
  private dragon?: Phaser.GameObjects.Image;
  private narrativeTexts: Phaser.GameObjects.Text[] = [];
  private devText?: Phaser.GameObjects.Text;
  private skipHint?: Phaser.GameObjects.Text;
  private fireEmitter?: Phaser.GameObjects.Particles.ParticleEmitter;
  private breathOverlay?: Phaser.GameObjects.Rectangle;

  // Root container (rotated in portrait)
  private root!: Phaser.GameObjects.Container;

  // Virtual (landscape) coordinate system
  private virtualW = 0;
  private virtualH = 0;
  private isPortrait = false;

  constructor() {
    super('IntroScene');
  }

  preload() {
    this.load.image('intro_bg', getAssetUrl('intro_bg_01.png'));
    this.load.image('intro_bg_02', getAssetUrl('intro_bg_02.png'));
    this.load.image('intro_bg_03', getAssetUrl('intro_bg_03.png'));
    this.load.image('intro_bg_04', getAssetUrl('intro_bg_04.png'));
    this.load.image('intro_bg_05', getAssetUrl('intro_bg_05.png'));
    this.load.image('intro_dragon', getAssetUrl('intro_dragon_02.png'));
  }

  private createNarrativeText(text: string, color: string = '#ef4444') {
    const t = this.add
      .text(0, 0, text, {
        fontFamily: 'serif',
        fontSize: '40px',
        color,
        align: 'center',
        fontStyle: 'italic',
        stroke: '#000000',
        strokeThickness: 4,
      })
      .setOrigin(0.5)
      .setAlpha(0)
      .setDepth(10);

    this.root.add(t);
    this.narrativeTexts.push(t);
    return t;
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.root = this.add.container(0, 0);

    if (!this.textures.exists('intro_flame')) {
      const graphics = this.make.graphics({ x: 0, y: 0 });
      graphics.fillStyle(0xff5500, 1).fillCircle(16, 16, 16).generateTexture('intro_flame', 32, 32).destroy();
    }

    this.input.once('pointerdown', () => {
      this.game.events.emit('intro-complete');
    });

    this.skipHint = this.add.text(0, 0, 'Touch anywhere to skip', {
      fontFamily: 'sans-serif', fontSize: '12px', color: '#57534e', fontStyle: 'bold'
    }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.skipHint);

    const keys = ['intro_bg', 'intro_bg_02', 'intro_bg_03', 'intro_bg_04', 'intro_bg_05'];
    keys.forEach(key => {
      const img = this.add.image(0, 0, key).setAlpha(0).setDepth(1);
      this.root.add(img);
      this.bgs.push(img);
    });

    this.dragon = this.add.image(0, 0, 'intro_dragon').setDepth(2).setVisible(false);
    this.root.add(this.dragon);

    this.devText = this.add.text(0, 0, "CRYINGDEV STUDIO\nPRESENTS", {
      fontFamily: 'serif', fontSize: '45px', color: '#a8a29e', align: 'center', fontStyle: 'bold'
    }).setOrigin(0.5).setAlpha(0).setDepth(10);
    this.root.add(this.devText);

    const n1 = this.createNarrativeText("FIASCO,\nA MASTER OF DISASTER...", '#ef4444');
    const n2 = this.createNarrativeText("EVERTHING WE LOVED IS LOST...", '#ef4444');
    const n3 = this.createNarrativeText("BUT THE HAMMER IS STILL HERE.", '#ef4444');
    const nDespair = this.createNarrativeText("NEVER FORGET...", '#ef4444');
    const nVengeance = this.createNarrativeText("AND FORGED A VENGEANCE.", '#f59e0b');

    this.breathOverlay = this.add.rectangle(0, 0, 10, 10, 0xff4400)
      .setAlpha(0).setDepth(5).setBlendMode(Phaser.BlendModes.ADD);
    this.root.add(this.breathOverlay);

    this.fireEmitter = this.add.particles(0, 0, 'intro_flame', {
      speedY: { min: 1200, max: 2200 },
      speedX: { min: -600, max: 600 },
      scale: { start: 6, end: 15 },
      alpha: { start: 1, end: 0 },
      lifespan: 1500,
      quantity: 40,
      blendMode: 'ADD',
      emitting: false
    });
    this.fireEmitter.setDepth(4);
    this.root.add(this.fireEmitter);

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.startSequence(n1, n2, n3, nDespair, nVengeance);
    this.time.delayedCall(0, () => this.handleResize());
  }

  private toVirtual(sx: number, sy: number) {
    if (!this.isPortrait) return { x: sx, y: sy };
    return { x: sy, y: this.virtualH - sx };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const screenW = gameSize?.width ?? this.scale.gameSize.width;
    const screenH = gameSize?.height ?? this.scale.gameSize.height;

    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    const w = this.virtualW;
    const h = this.virtualH;
    const centerX = w / 2;
    const centerY = h / 2;

    this.cameras.main.setViewport(0, 0, screenW, screenH);
    // More aggressive scaling for small heights
    const uiScale = Phaser.Math.Clamp(Math.min(w, h) / 720, 0.4, 1.2);

    this.bgs.forEach(img => {
      img.setPosition(centerX, centerY);
      const s = Math.max(w / img.width, h / img.height);
      img.setScale(s);
    });

    if (this.dragon) {
      const dScaleByHeight = (h * 0.55) / this.dragon.height;
      const dScaleByWidth  = (w * 0.90) / this.dragon.width;
      const dScale = Math.min(dScaleByHeight, dScaleByWidth);
      this.dragon.setScale(dScale);
      this.dragon.setPosition(centerX, centerY - h * 0.22); // Slightly higher for more space
    }

    if (this.devText) {
      this.devText.setPosition(centerX, centerY);
      this.devText.setFontSize(Math.round(45 * uiScale));
    }

    if (this.skipHint) {
      this.skipHint.setPosition(centerX, h - Math.max(24, h * 0.05));
      this.skipHint.setFontSize(Math.round(12 * uiScale));
    }

    if (this.breathOverlay) {
      this.breathOverlay.setPosition(centerX, centerY).setSize(w, h);
    }

    this.narrativeTexts.forEach(t => {
      t.setPosition(centerX, centerY);
      t.setFontSize(Math.round(40 * uiScale));
    });

    const despairIdx = this.narrativeTexts.length - 2;
    const gap = Math.max(20, h * 0.08); // Responsive gap
    if (this.narrativeTexts[despairIdx]) this.narrativeTexts[despairIdx].y = centerY - gap / 2;
    if (this.narrativeTexts[despairIdx + 1]) this.narrativeTexts[despairIdx + 1].y = centerY + gap / 2;

    if (this.fireEmitter) {
      if (this.dragon) {
        const mouthY = this.dragon.y + this.dragon.displayHeight * 0.12;
        this.fireEmitter.setPosition(centerX, mouthY);
      } else {
        this.fireEmitter.setPosition(centerX, h * 0.35);
      }
    }
  }

  private startSequence(n1: any, n2: any, n3: any, nD: any, nV: any) {
    this.tweens.chain({
      tweens: [
        { targets: this.devText, alpha: 1, duration: 2500, ease: 'Power2' },
        { targets: this.devText, alpha: 1, duration: 2000, onStart: () => this.cameras.main.shake(6000, 0.005) },
        { targets: this.devText, alpha: 0, duration: 2000, ease: 'Power2' },
        { targets: this.bgs[0], alpha: 1, duration: 1500, ease: 'Linear' },
        {
          targets: this.dragon,
          alpha: { from: 0, to: 1 },
          duration: 3000,
          ease: 'Sine.easeInOut',
          hold: 500,
          onStart: () => {
              this.dragon!.setVisible(true);
              this.cameras.main.shake(3500, 0.005); 
          }
        },
        { targets: this.dragon, y: '-=150', scale: '*=0.7', duration: 1000, ease: 'Quad.easeOut' },
        {
            targets: this.breathOverlay,
            alpha: 0.8,
            duration: 2500,
            yoyo: true, hold: 100,
            onStart: () => {
                this.fireEmitter!.start();
                this.cameras.main.shake(2500, 0.03);
            },
            onComplete: () => {
                this.fireEmitter!.stop();
                this.dragon!.setVisible(false);
            }
        },
        { targets: this.bgs[1], alpha: 1, duration: 2000, hold: 2500, ease: 'Linear' },
        { targets: n1, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n1, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[2], alpha: 1, duration: 2000, hold: 2500, ease: 'Linear' },
        { targets: n2, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n2, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[3], alpha: 1, duration: 3000, hold: 3500, ease: 'Linear' },
        { targets: n3, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n3, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[4], alpha: 1, duration: 3000, ease: 'Linear' },
        { targets: nD, alpha: 1, duration: 2000, ease: 'Power2', delay: 500 },
        { targets: nV, alpha: 1, duration: 2500, ease: 'Power2' },
        {
          targets: [...this.bgs, nD, nV],
          alpha: 0,
          duration: 3000,
          delay: 3000,
          onComplete: () => {
            this.game.events.emit('intro-complete');
          }
        }
      ]
    });
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { User, ChevronRight, Coins } from 'lucide-react';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface ItemDetail {
  icon: string;
  imageUrl?: string;
  price: number;
}

interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
  highlightTerm?: string;
  itemDetail?: ItemDetail;
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ 
  speaker, 
  text, 
  options = [], 
  highlightTerm,
  itemDetail 
}) => {
  const [displayedText, setDisplayedText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [showItemTooltip, setShowItemTooltip] = useState(false);
  const isMounted = useRef(true);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  useEffect(() => {
    setDisplayedText('');
    setIsTyping(true);
    setShowItemTooltip(false);
    let index = 0;
    const speed = 25; 

    const timer = setInterval(() => {
      if (!isMounted.current) return;

      index++;
      if (index > text.length) {
        clearInterval(timer);
        setIsTyping(false);
        setDisplayedText(text);
      } else {
        setDisplayedText(text.slice(0, index));
      }
    }, speed);

    return () => clearInterval(timer);
  }, [text]);

  useEffect(() => {
    if (scrollRef.current) {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [displayedText]);

  const handleSkipTyping = () => {
    if (isTyping) {
      setDisplayedText(text);
      setIsTyping(false);
    }
  };

  // Helper to render text with highlighting
  const renderFormattedText = () => {
    if (!highlightTerm || !displayedText.includes(highlightTerm)) {
      return displayedText;
    }

    const parts = displayedText.split(new RegExp(`(${highlightTerm})`, 'g'));
    return parts.map((part, i) => 
      part === highlightTerm ? (
        <span 
          key={i} 
          className="text-emerald-400 font-black underline decoration-emerald-500/30 underline-offset-4 cursor-help relative group"
          onMouseEnter={() => setShowItemTooltip(true)}
          onMouseLeave={() => setShowItemTooltip(false)}
          onClick={(e) => { e.stopPropagation(); setShowItemTooltip(!showItemTooltip); }}
        >
          {part}
          {/* Tooltip Popup */}
          {itemDetail && (
            <span className={`absolute bottom-full left-1/2 -translate-x-1/2 mb-4 px-4 py-3 bg-stone-900/95 backdrop-blur-xl border-2 border-emerald-500/50 rounded-2xl shadow-[0_10px_30px_rgba(0,0,0,0.5)] flex items-center gap-3 transition-all duration-300 min-w-max z-[100] ${showItemTooltip ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-2 pointer-events-none'}`}>
               <div className="w-10 h-10 md:w-12 md:h-12 bg-stone-800 rounded-xl border border-stone-700 flex items-center justify-center shadow-inner shrink-0">
                  {itemDetail.imageUrl ? (
                    <img src={itemDetail.imageUrl} className="w-7 h-7 md:w-9 md:h-9 object-contain" />
                  ) : (
                    <span className="text-xl md:text-2xl">{itemDetail.icon}</span>
                  )}
               </div>
               <div className="flex flex-col leading-none">
                  <span className="text-[10px] text-stone-500 font-black uppercase tracking-widest mb-1">Asking Price</span>
                  <div className="flex items-center gap-1.5 text-emerald-400 font-mono font-black text-sm md:text-xl">
                    <Coins className="w-4 h-4 md:w-5 md:h-5" />
                    {itemDetail.price} G
                  </div>
               </div>
               <div className="absolute top-full left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] border-l-transparent border-r-[8px] border-r-transparent border-t-[8px] border-t-emerald-500/50"></div>
            </span>
          )}
        </span>
      ) : part
    );
  };

  return (
    <div className="absolute bottom-2 md:bottom-6 left-1/2 -translate-x-1/2 w-[96vw] md:w-[90vw] max-w-6xl z-40">
      <div 
        className="w-full h-[30vh] min-h-[120px] bg-stone-950/20 backdrop-blur-3xl border border-white/10 md:border-2 rounded-2xl md:rounded-3xl shadow-[0_40px_80px_rgba(0,0,0,0.7)] flex flex-row overflow-hidden animate-in slide-in-from-bottom-10 fade-in duration-500 ring-1 ring-white/10"
      >

        {/* Speaker Name Badge - Reduced padding for landscape */}
        <div className="bg-stone-900/10 p-2 md:p-6 border-r border-white/5 flex flex-col items-center gap-1 md:gap-4 w-24 md:w-44 shrink-0 justify-center">
          <div className="w-10 h-10 md:w-20 md:h-20 rounded-full bg-gradient-to-br from-amber-900/20 to-stone-800/40 border border-amber-600/20 flex items-center justify-center shadow-inner">
             <User className="w-5 h-5 md:w-10 md:h-10 text-amber-500/80 drop-shadow-[0_0_12px_rgba(245,158,11,0.4)]" />
          </div>
          <div className="flex flex-col items-center">
              <span className="font-black text-amber-50 text-[10px] md:text-xl text-center font-serif leading-tight tracking-tight drop-shadow-md truncate w-full">
                {speaker}
              </span>
          </div>
        </div>

        {/* Text Area Content - Responsive spacing */}
        <div className="flex-1 p-3 md:p-8 relative flex flex-col min-h-0 bg-gradient-to-br from-white/5 to-transparent">
          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto custom-scrollbar pr-2 cursor-pointer"
            onClick={handleSkipTyping}
          >
            <div 
              className={`text-xs md:text-2xl text-stone-50 leading-snug md:leading-relaxed font-medium drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] transition-opacity duration-300 ${isTyping ? 'after:content-["_"] after:inline-block after:w-2 after:h-4 md:after:h-5 after:bg-amber-500 after:animate-pulse after:ml-1' : ''}`}
            >
              {renderFormattedText()}
            </div>
          </div>

          {/* Options - More compact buttons for small height */}
          {!isTyping && options.length > 0 && (
            <div className="mt-2 md:mt-6 flex flex-wrap gap-2 md:gap-4 justify-end animate-in fade-in slide-in-from-right-4 pb-1 shrink-0">
              {options.map((option, idx) => (
                <button
                  key={idx}
                  onClick={option.action}
                  disabled={option.disabled}
                  className={`px-3 md:px-8 py-1.5 md:py-4 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm flex items-center gap-1.5 md:gap-2 transition-all transform active:scale-95 border shadow-2xl ${
                    option.disabled 
                      ? 'bg-stone-800/40 text-stone-600 border-stone-700/30 cursor-not-allowed'
                      : option.variant === 'danger'
                        ? 'bg-red-900/60 text-red-50 border-red-800/50 hover:bg-red-700 hover:border-red-400'
                        : option.variant === 'neutral'
                            ? 'bg-stone-800/60 text-stone-100 border-stone-600 hover:bg-stone-700 hover:border-stone-400'
                            : 'bg-amber-700/80 text-white border-amber-500 hover:bg-amber-600 hover:border-amber-300 hover:shadow-amber-900/60'
                  }`}
                >
                  {option.label}
                  {!option.disabled && <ChevronRight className="w-2.5 h-2.5 md:w-5 md:h-5 opacity-70 group-hover:translate-x-1 transition-transform" />}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DialogueBox;

import React, { useState, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { Store, Coins, PackageOpen, Heart, Users, ArrowLeft, ZapOff } from 'lucide-react';
import { EQUIPMENT_ITEMS } from '../../../data/equipment';
import { MATERIALS } from '../../../data/materials';
import { getAssetUrl } from '../../../utils';
import { GAME_CONFIG } from '../../../config/game-config';

interface ShopTabProps {
    onNavigate: (tab: any) => void;
}

const ShopSign = ({ isOpen, onToggle, disabled }: { isOpen: boolean, onToggle: () => void, disabled: boolean }) => {
    return (
        <div className="absolute top-2 md:top-4 right-2 md:right-4 z-50 flex flex-col items-center">
            <div className="flex justify-around w-16 md:w-24 h-4 md:h-6 px-4">
                <div className="w-0.5 md:w-1 bg-stone-600 rounded-full"></div>
                <div className="w-0.5 md:w-1 bg-stone-600 rounded-full"></div>
            </div>

            <button 
                onClick={onToggle}
                disabled={disabled}
                className={`group relative w-24 md:w-36 h-10 md:h-16 perspective-1000 cursor-pointer disabled:cursor-not-allowed`}
            >
                <div className={`relative w-full h-full transition-transform duration-700 preserve-3d ${isOpen ? '' : 'rotate-y-180'}`}>
                    <div className="absolute inset-0 backface-hidden bg-[#5d4037] border md:border-2 border-[#3e2723] rounded shadow-lg flex flex-col items-center justify-center p-0.5 md:p-1">
                        <div className="w-full h-full border border-[#795548]/30 rounded flex flex-col items-center justify-center">
                             <span className="text-[8px] md:text-[10px] text-[#8d6e63] font-bold uppercase tracking-widest leading-none">The Forge is</span>
                             <span className="text-sm md:text-xl font-black text-emerald-400 font-serif tracking-tighter drop-shadow-sm">OPEN</span>
                        </div>
                    </div>
                    <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#3e2723] border md:border-2 border-[#1b0000] rounded shadow-lg flex flex-col items-center justify-center p-0.5 md:p-1">
                        <div className="w-full h-full border border-[#5d4037]/30 rounded flex flex-col items-center justify-center">
                             <span className="text-[8px] md:text-[10px] text-[#5d4037] font-bold uppercase tracking-widest leading-none">The Forge is</span>
                             <span className="text-sm md:text-xl font-black text-stone-500 font-serif tracking-tighter drop-shadow-sm">CLOSED</span>
                        </div>
                    </div>
                </div>
            </button>
        </div>
    );
};

const ShopTab: React.FC<ShopTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();
  const { isShopOpen } = state.forge;
  const { activeCustomer, shopQueue } = state;
  const [counterImgError, setCounterImgError] = useState(false);

  const getItemName = (id: string) => {
    const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
    if (eq) return eq.name;
    const res = Object.values(MATERIALS).find(i => i.id === id);
    return res ? res.name : id;
  };

  const getItemImageUrl = (id: string) => {
      const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
      if (eq && eq.image) return getAssetUrl(eq.image);
      const res = Object.values(MATERIALS).find(i => i.id === id);
      if (res) return getAssetUrl(`${res.id}.png`);
      return getAssetUrl(`${id}.png`);
  };

  const getItemIcon = (id: string) => {
      const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
      if (eq) return eq.icon;
      return '📦';
  };

  const handleSell = () => {
      if (!activeCustomer) return;
      const { mercenary, request } = activeCustomer;
      if (request.type === 'RESOURCE') {
          actions.sellItem(request.requestedId, 1, request.price, undefined, mercenary);
      } else {
          const matchingItem = state.inventory.find(i => i.equipmentData && i.id.startsWith(request.requestedId));
          if (matchingItem) actions.sellItem(matchingItem.id, 1, request.price, matchingItem.id, mercenary);
      }
  };

  const handleRefuse = () => actions.dismissCustomer();
  const handleToggleShop = () => actions.toggleShop();

  const hasItem = () => {
      if (!activeCustomer) return false;
      const { request } = activeCustomer;
      if (request.type === 'RESOURCE') {
          const item = state.inventory.find(i => i.id === request.requestedId);
          return item && item.quantity > 0;
      } else {
          return state.inventory.some(i => i.id.startsWith(request.requestedId));
      }
  };

  const canAffordOpen = state.stats.energy >= GAME_CONFIG.ENERGY_COST.OPEN_SHOP;

  return (
    <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">

        <div className="absolute inset-0 z-0">
            <img 
                src={getAssetUrl('shop_bg.jpeg')} 
                alt="Shop Interior" 
                className="absolute top-0 opacity-60 w-full h-full object-cover"
                onError={(e) => {
                    e.currentTarget.style.display = 'none';
                    e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #292524, #1c1917)';
                }}
            />
        </div>

        <ShopSign 
            isOpen={isShopOpen} 
            onToggle={handleToggleShop} 
            disabled={!isShopOpen && !canAffordOpen}
        />

        {isShopOpen && (
            <div className="absolute top-2 md:top-4 right-32 md:right-44 z-50 flex items-center gap-1.5 md:gap-2 bg-stone-900/90 px-2 md:px-4 py-1 md:py-2 rounded-xl border border-stone-700 text-stone-200 shadow-xl backdrop-blur-md">
                <div className="bg-stone-800 p-1 md:p-1.5 rounded-full">
                    <Users className="w-3 h-3 md:w-5 md:h-5 text-amber-500" />
                </div>
                <div className="flex flex-col leading-none">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-bold uppercase tracking-wider">Queue</span>
                    <span className="text-sm md:text-lg font-bold font-mono">{shopQueue.length}</span>
                </div>
            </div>
        )}

        {isShopOpen && activeCustomer && (
            <div className="absolute top-[8%] md:top-[10%] left-4 md:left-10 z-50 animate-in slide-in-from-left-10 fade-in duration-500">
                <div className="w-36 md:w-48 bg-stone-950/80 border border-stone-700/50 p-2 md:p-3 rounded-2xl backdrop-blur-xl shadow-2xl text-[9px] md:text-xs ring-1 ring-white/10">
                    <div className="flex items-center justify-between mb-1.5 md:mb-2">
                        <span className="font-black text-amber-500 uppercase tracking-tighter">{activeCustomer.mercenary.job}</span>
                        <span className="text-stone-500 font-mono">Lv.{activeCustomer.mercenary.level}</span>
                    </div>
                    <div className="space-y-1 mb-1.5 md:mb-2">
                        <div className="w-full bg-stone-900 h-1 md:h-1.5 rounded-full overflow-hidden border border-white/5 shadow-inner">
                            <div className="bg-red-600 h-full shadow-[0_0_10px_rgba(220,38,38,0.5)]" style={{ width: `${(activeCustomer.mercenary.currentHp / activeCustomer.mercenary.maxHp) * 100}%` }}></div>
                        </div>
                        <div className="w-full bg-stone-900 h-1 md:h-1.5 rounded-full overflow-hidden border border-white/5 shadow-inner">
                            <div className="bg-blue-600 h-full shadow-[0_0_10px_rgba(37,99,235,0.5)]" style={{ width: `${(activeCustomer.mercenary.currentMp / activeCustomer.mercenary.maxMp) * 100}%` }}></div>
                        </div>
                    </div>
                    <div className="flex items-center gap-1.5 text-pink-500 font-black">
                        <Heart className="w-3 h-3 fill-pink-500" />
                        <span>{activeCustomer.mercenary.affinity}</span>
                    </div>
                </div>
            </div>
        )}

        {/* Character Placement - Responsive Scaling based on dvh */}
        <div className="absolute inset-0 z-20 w-full h-full flex flex-col items-center justify-end pointer-events-none pb-0">
            {isShopOpen && activeCustomer && (
               <div className="relative flex justify-center items-end w-full animate-in fade-in zoom-in-95 duration-500 ease-out">
                   <div className="relative h-[100dvh] md:h-[110dvh] w-auto flex justify-center translate-y-[20dvh] md:translate-y-[25dvh]">
                       <img 
                           src={activeCustomer.mercenary.sprite ? getAssetUrl(activeCustomer.mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')} 
                           alt="Adventurer"
                           className="h-full object-contain object-bottom filter drop-shadow-[0_0_60px_rgba(0,0,0,0.9)]"
                       />
                   </div>
               </div>
            )}
        </div>

        <div className="absolute bottom-0 w-full h-24 md:h-40 z-30 flex items-end justify-center pointer-events-none">
            {!counterImgError ? (
                <img 
                    src={getAssetUrl('shop_counter.png')}
                    alt="Shop Counter"
                    className="w-full h-full object-cover object-top filter drop-shadow-[0_-15px_30px_rgba(0,0,0,0.6)]"
                    onError={() => setCounterImgError(true)}
                />
            ) : (
                <div className="w-full h-full bg-[#3f2e22] border-t-2 md:border-t-[8px] border-[#5d4037] shadow-[0_-20px_40px_rgba(0,0,0,0.7)] relative overflow-hidden">
                    <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, #000 10px, #000 12px)' }}></div>
                </div>
            )}
        </div>

        {isShopOpen && activeCustomer && (
            <DialogueBox 
                speaker={activeCustomer.mercenary.name}
                text={activeCustomer.request.dialogue}
                highlightTerm={getItemName(activeCustomer.request.requestedId)}
                itemDetail={{
                    icon: getItemIcon(activeCustomer.request.requestedId),
                    imageUrl: getItemImageUrl(activeCustomer.request.requestedId),
                    price: activeCustomer.request.price
                }}
                options={[
                    { label: `Sell (${activeCustomer.request.price} G)`, action: handleSell, variant: 'primary', disabled: !hasItem() },
                    { label: "Refuse", action: handleRefuse, variant: 'danger' }
                ]}
            />
        )}

        {!isShopOpen && (
            <div className="absolute inset-0 z-40 flex items-center justify-center pointer-events-none">
                <div className="absolute inset-0 bg-black/70 backdrop-blur-sm transition-opacity duration-1000 animate-in fade-in"></div>
                <div className="relative z-10 flex flex-col items-center animate-in zoom-in-95 duration-500">
                    {!canAffordOpen ? (
                        <div className="bg-stone-950/90 border-2 border-red-900/50 p-6 md:p-10 rounded-[2rem] shadow-2xl flex flex-col items-center text-center max-w-xs ring-4 ring-black/50 backdrop-blur-2xl">
                            <div className="w-16 h-16 md:w-20 md:h-20 bg-red-950/30 rounded-full flex items-center justify-center mb-4 border border-red-800/30">
                                <ZapOff className="w-8 h-8 md:w-10 md:h-10 text-red-500 animate-pulse" />
                            </div>
                            <h3 className="text-xl md:text-2xl font-black text-red-100 font-serif uppercase tracking-tight">Exhausted</h3>
                            <p className="text-stone-500 text-xs md:text-base mt-2 mb-6 leading-relaxed">
                                You lack the energy to manage the counter. Take a rest to recover.
                            </p>
                            <button onClick={() => onNavigate('FORGE')} className="w-full py-3 md:py-4 bg-stone-900 hover:bg-stone-800 text-stone-200 rounded-xl font-black text-xs md:text-sm transition-all border border-stone-700 pointer-events-auto flex items-center justify-center gap-2 uppercase tracking-widest"><ArrowLeft className="w-4 h-4" />Back to Forge</button>
                        </div>
                    ) : (
                        <div className="text-center group">
                             <div className="w-20 h-20 md:w-24 md:h-24 bg-stone-900/80 rounded-full flex items-center justify-center mx-auto mb-4 border border-stone-700/50 backdrop-blur-xl shadow-2xl transition-transform group-hover:scale-110 duration-700 ring-1 ring-white/5">
                                <Store className="w-8 h-8 md:w-10 md:h-10 text-stone-500" />
                            </div>
                            <h3 className="text-2xl md:text-4xl font-black text-stone-300 font-serif tracking-tighter drop-shadow-2xl uppercase">Shop is Closed</h3>
                            <p className="text-stone-500 text-sm md:text-lg mt-2 font-black uppercase tracking-widest opacity-60">Flip the sign to welcome travelers</p>
                        </div>
                    )}
                </div>
            </div>
        )}

        {isShopOpen && !activeCustomer && (
            <div className="absolute inset-0 z-20 flex flex-col items-center justify-center pointer-events-none pb-20">
                <div className="text-center animate-in fade-in zoom-in duration-1000">
                    <div className="w-20 h-20 md:w-28 md:h-28 bg-black/40 rounded-full flex items-center justify-center mx-auto mb-4 border border-white/10 backdrop-blur-xl shadow-inner">
                        <Store className="w-10 h-10 md:w-12 md:h-12 text-stone-700 animate-pulse" />
                    </div>
                    <h3 className="text-lg md:text-2xl font-black text-stone-500 uppercase tracking-[0.3em] opacity-40">Awaiting Customers</h3>
                </div>
            </div>
        )}
    </div>
  );
};

export default ShopTab;

import React, { useState, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { ArrowLeft, Heart, Coins, Gift, MessageSquare, UserPlus, Info, Zap, Package, X, ChevronRight, Search, Wrench, LogOut, Star } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { Mercenary } from '../../../models/Mercenary';
import { CONTRACT_CONFIG, calculateHiringCost } from '../../../config/contract-config';
import { InventoryItem } from '../../../types/inventory';
import MercenaryDetailModal from '../../modals/MercenaryDetailModal';

interface TavernInteractionProps {
    mercenary: Mercenary;
    onBack: () => void;
}

const TavernInteraction: React.FC<TavernInteractionProps> = ({ mercenary, onBack }) => {
    const { state, actions } = useGame();
    const [dialogue, setDialogue] = useState(`(You sit across from ${mercenary.name}.)`);
    const [showGiftMenu, setShowGiftMenu] = useState(false);
    const [showDetail, setShowDetail] = useState(false);
    const [pendingGiftItem, setPendingGiftItem] = useState<InventoryItem | null>(null);

    const isHired = mercenary.status === 'HIRED' || mercenary.status === 'ON_EXPEDITION' || mercenary.status === 'INJURED';
    const hiringCost = calculateHiringCost(mercenary.level, mercenary.job);
    const canAfford = state.stats.gold >= hiringCost;
    const hasAffinity = mercenary.affinity >= CONTRACT_CONFIG.HIRE_AFFINITY_THRESHOLD;

    const handleTalk = () => {
        if (pendingGiftItem) return;
        const lines = [
            "The road is long, but a warm fire makes it easier.",
            "I heard rumors of rare ores in the Rat Cellar...",
            "What's your specialty, smith? I need something that won't break.",
            "Business seems slow today. Maybe I can help with that later.",
            "I've seen many forges, but yours has... potential.",
            "Tell me, do you have any ale left?",
            "I'm looking for work. Something that pays in gold and glory."
        ];
        setDialogue(lines[Math.floor(Math.random() * lines.length)]);
    };

    const handleRecruit = () => {
        if (pendingGiftItem) return;
        if (!hasAffinity) {
            setDialogue("I don't know you well enough to pledge my blade to your forge yet.");
            return;
        }
        if (!canAfford) {
            setDialogue(`The contract is ${hiringCost} gold. Come back when you have the coin.`);
            return;
        }
        actions.hireMercenary(mercenary.id, hiringCost);
        setDialogue("A fair contract. My strength is yours, Lockhart.");
    };

    const handleSelectItemForGift = (item: InventoryItem) => {
        setPendingGiftItem(item);
        setShowGiftMenu(false);
        const raritySuffix = item.type === 'EQUIPMENT' ? ` (${item.equipmentData?.rarity})` : '';
        setDialogue(`(You hold out the ${item.name}${raritySuffix}.) "Would you like this?"`);
    };

    const handleConfirmGift = () => {
        if (!pendingGiftItem) return;
        const item = pendingGiftItem;
        actions.giveGift(mercenary.id, item.id);
        if (item.type === 'EQUIPMENT') {
            setDialogue(`(Surprised) "Is this for me? A ${item.name}? I will carry it with honor."`);
        } else {
            setDialogue(`${mercenary.name} seems pleased with the gift. "For me? You're too kind."`);
        }
        setPendingGiftItem(null);
    };

    const handleCancelGift = () => {
        setPendingGiftItem(null);
        setDialogue(`(You pull your hand back.) "Actually, never mind."`);
    };

    const giftableItems = state.inventory.filter(i => 
        i.type === 'RESOURCE' || 
        i.type === 'CONSUMABLE' || 
        i.type === 'EQUIPMENT'
    );

    const getRarityColor = (rarity?: string) => {
        switch (rarity) {
            case 'Common': return 'text-stone-400';
            case 'Uncommon': return 'text-emerald-400';
            case 'Rare': return 'text-blue-400';
            case 'Epic': return 'text-purple-400';
            case 'Legendary': return 'text-amber-400';
            default: return 'text-stone-500';
        }
    };

    return (
        <div className="relative h-full w-full bg-stone-950 overflow-hidden flex flex-col items-center justify-center">

            {/* Background */}
            <div className="absolute inset-0 z-0">
                <img 
                    src={getAssetUrl('tavern_bg.jpeg')} 
                    alt="Tavern Interior" 
                    className="absolute inset-0 w-full h-full object-cover opacity-50"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #1c1917, #0c0a09)';
                    }}
                />
                <div className="absolute inset-0 bg-black/40"></div>
            </div>

            {/* Mercenary Vitals - TOP LEFT */}
            <div className="absolute top-4 left-4 z-40 animate-in slide-in-from-left-4 duration-500">
                <div className="bg-stone-900/90 border border-stone-700 p-3 rounded-xl backdrop-blur-md shadow-2xl min-w-[180px]">
                    <div className="flex justify-between items-center mb-2">
                        <div className="flex flex-col leading-tight">
                            <span className="font-black text-amber-500 text-[8px] tracking-widest uppercase">{mercenary.job}</span>
                            <span className="text-stone-500 text-[8px] font-mono">Lv.{mercenary.level}</span>
                        </div>
                        <div className="flex items-center gap-1 text-pink-400 font-bold bg-pink-950/20 px-1.5 py-0.5 rounded border border-pink-900/30">
                            <Heart className="w-2.5 h-2.5 fill-pink-400" />
                            <span className="font-mono text-xs">{mercenary.affinity}</span>
                        </div>
                    </div>

                    <div className="space-y-1.5">
                        <div className="flex flex-col gap-0.5">
                            <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-stone-800">
                                <div className="bg-red-600 h-full transition-all duration-700" style={{ width: `${(mercenary.currentHp / mercenary.maxHp) * 100}%` }}></div>
                            </div>
                        </div>
                        <div className="flex flex-col gap-0.5">
                            <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-stone-800">
                                <div className="bg-blue-600 h-full transition-all duration-700" style={{ width: `${(mercenary.currentMp / mercenary.maxMp) * 100}%` }}></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Character Sprite Rendering - DVH BASED SCALING */}
            <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none pb-0">
               <div className="relative flex justify-center items-end w-full animate-in fade-in zoom-in-95 duration-700 ease-out">
                   <div className="relative h-[90dvh] md:h-[110dvh] w-auto flex justify-center translate-y-[12dvh] md:translate-y-[20dvh]">
                       <img 
                           src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')} 
                           alt={mercenary.name}
                           className="h-full object-contain object-bottom filter drop-shadow-[0_0_80px_rgba(0,0,0,0.95)]"
                       />
                       <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-64 h-10 bg-black/60 blur-2xl rounded-full -z-10"></div>
                   </div>
               </div>
            </div>

            {/* INTERACTION MENU */}
            <div className={`absolute right-4 top-4 z-50 grid grid-cols-2 gap-2 w-60 md:w-80 animate-in slide-in-from-right-8 duration-700 delay-200 transition-opacity ${pendingGiftItem ? 'opacity-30 pointer-events-none grayscale' : 'opacity-100'}`}>

                <button 
                    onClick={onBack}
                    className="col-span-2 flex items-center gap-2 p-2 bg-red-950/30 hover:bg-red-900/50 border border-red-900/40 hover:border-red-500 rounded-xl backdrop-blur-md transition-all shadow-xl group"
                >
                    <div className="bg-red-900/20 p-1.5 rounded-lg group-hover:text-red-400 transition-colors text-red-700 border border-red-900/30">
                        <LogOut className="w-4 h-4" />
                    </div>
                    <span className="font-bold text-[11px] md:text-xs text-red-200 group-hover:text-white uppercase tracking-widest">Leave</span>
                </button>

                <button 
                    onClick={handleTalk}
                    className="flex items-center gap-2 p-2 bg-stone-900/90 hover:bg-stone-800 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl group"
                >
                    <div className="bg-stone-800 p-1.5 rounded-lg group-hover:bg-amber-900/30 group-hover:text-amber-500 transition-colors text-stone-500 group-hover:text-amber-500">
                        <MessageSquare className="w-4 h-4" />
                    </div>
                    <span className="font-bold text-[11px] md:text-xs text-stone-300">Talk</span>
                </button>

                <button 
                    onClick={() => setShowGiftMenu(true)}
                    className="flex items-center gap-2 p-2 bg-stone-900/90 hover:bg-stone-800 border border-stone-700 hover:border-pink-500 rounded-xl backdrop-blur-md transition-all shadow-xl group"
                >
                    <div className="bg-stone-800 p-1.5 rounded-lg group-hover:bg-pink-900/30 group-hover:text-pink-500 transition-colors text-stone-500 group-hover:text-pink-500">
                        <Gift className="w-4 h-4" />
                    </div>
                    <span className="font-bold text-[11px] md:text-xs text-stone-300">Gift</span>
                </button>

                {!isHired && (
                    <button 
                        onClick={handleRecruit}
                        disabled={!canAfford || !hasAffinity}
                        className={`flex items-center gap-2 p-2 border rounded-xl backdrop-blur-md transition-all shadow-xl group relative overflow-hidden ${
                            (!canAfford || !hasAffinity) 
                            ? 'bg-stone-950/80 border-stone-800 text-stone-600 grayscale cursor-not-allowed' 
                            : 'bg-amber-900/40 hover:bg-amber-800/60 border-amber-600/50 hover:border-amber-400 text-amber-100'
                        }`}
                    >
                        <div className={`p-1.5 rounded-lg transition-colors ${(!canAfford || !hasAffinity) ? 'bg-stone-900 text-stone-700' : 'bg-amber-950/50 group-hover:text-amber-400 text-amber-600'}`}>
                            <UserPlus className="w-4 h-4" />
                        </div>
                        <div className="flex flex-col items-start leading-tight">
                            <span className="font-bold text-[10px] md:text-xs uppercase">Recruit</span>
                            <span className={`text-[8px] md:text-[9px] font-mono ${(!canAfford || !hasAffinity) ? 'text-stone-700' : 'text-amber-500/70'}`}>
                                {hiringCost}G
                            </span>
                        </div>
                    </button>
                )}

                <button 
                    onClick={() => setShowDetail(true)}
                    className={`flex items-center gap-2 p-2 bg-stone-900/90 hover:bg-stone-800 border border-stone-700 rounded-xl backdrop-blur-md transition-all shadow-xl group ${isHired ? 'hover:border-emerald-500' : 'hover:border-blue-500'}`}
                >
                    <div className={`bg-stone-800 p-1.5 rounded-lg transition-colors text-stone-500 ${isHired ? 'group-hover:bg-emerald-900/30 group-hover:text-emerald-500' : 'group-hover:bg-blue-900/30 group-hover:text-blue-500'}`}>
                        {isHired ? <Wrench className="w-4 h-4" /> : <Search className="w-4 h-4" />}
                    </div>
                    <span className={`font-bold text-[11px] md:text-xs text-stone-300 ${isHired ? 'group-hover:text-emerald-200' : 'group-hover:text-blue-200'}`}>
                        {isHired ? 'Manage' : 'Inspect'}
                    </span>
                </button>
            </div>

            {/* Interaction Dialogue Area */}
            <DialogueBox 
                speaker={mercenary.name}
                text={dialogue}
                options={pendingGiftItem ? [
                    { label: `Give ${pendingGiftItem.name}`, action: handleConfirmGift, variant: 'primary' },
                    { label: "Cancel", action: handleCancelGift, variant: 'neutral' }
                ] : []}
            />

            {/* Gift Selection Overlay */}
            {showGiftMenu && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200 p-4">
                    <div className="bg-stone-900 border-2 border-stone-700 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 max-h-[85vh]">
                        <div className="p-3 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-2">
                                <div className="bg-pink-900/30 p-1.5 rounded-lg border border-pink-700/50">
                                    <Gift className="w-4 h-4 text-pink-500" />
                                </div>
                                <h3 className="font-bold text-stone-200 font-serif uppercase tracking-widest text-sm">Select Gift</h3>
                            </div>
                            <button onClick={() => setShowGiftMenu(false)} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500 hover:text-stone-300 transition-colors">
                                <X className="w-4 h-4" />
                            </button>
                        </div>
                        <div className="p-3 overflow-y-auto grid grid-cols-2 gap-2 custom-scrollbar flex-1 min-h-0">
                            {giftableItems.length === 0 ? (
                                <div className="col-span-2 py-12 text-center opacity-50">
                                    <Package className="w-8 h-8 text-stone-500 mx-auto mb-2" />
                                    <p className="text-[10px] text-stone-600 italic">Inventory is empty.</p>
                                </div>
                            ) : (
                                giftableItems.map(item => {
                                    const isEquipment = item.type === 'EQUIPMENT';
                                    const rarity = item.equipmentData?.rarity;
                                    const rarityColor = getRarityColor(rarity);

                                    return (
                                        <button 
                                            key={item.id} 
                                            onClick={() => handleSelectItemForGift(item)}
                                            className={`flex items-center gap-2 p-2 bg-stone-800 hover:bg-stone-750 border rounded-xl transition-all group text-left ${isEquipment ? 'border-amber-900/30' : 'border-stone-700'}`}
                                        >
                                            <div className="w-8 h-8 bg-stone-950 rounded-lg border border-stone-800 flex items-center justify-center text-lg shrink-0">
                                                {item.icon || (isEquipment ? '⚔️' : '🎁')}
                                            </div>
                                            <div className="min-w-0 flex-1">
                                                <div className={`text-[10px] font-bold truncate ${isEquipment ? 'text-stone-200' : 'text-stone-300'}`}>{item.name}</div>
                                                <div className="flex items-center gap-1 leading-none mt-0.5">
                                                    {isEquipment ? (
                                                        <span className={`text-[7px] font-black uppercase tracking-tighter ${rarityColor}`}>{rarity}</span>
                                                    ) : (
                                                        <div className="text-[8px] text-stone-500 font-mono">x{item.quantity}</div>
                                                    )}
                                                </div>
                                            </div>
                                        </button>
                                    );
                                })
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Mercenary Detail Modal */}
            {showDetail && (
                <MercenaryDetailModal 
                    mercenary={mercenary}
                    onClose={() => setShowDetail(false)}
                    onUnequip={(mercId, slot) => actions.unequipItem(mercId, slot)}
                    isReadOnly={!isHired}
                />
            )}
        </div>
    );
};

export default TavernInteraction;

import React, { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import { calculatePartyPower, calculateMercenaryPower, formatDuration } from '../../../utils/dungeonUtils';
import { Sword, Skull, Timer, Zap, Map as MapIcon, ChevronRight, Lock, CheckCircle, Trophy, User, XCircle } from 'lucide-react';
import { getAssetUrl } from '../../../utils';

const DungeonTab = () => {
    const { state, actions } = useGame();
    const { activeExpeditions, knownMercenaries, dungeonClearCounts } = state;

    const [selectedDungeonId, setSelectedDungeonId] = useState<string | null>(null);
    const [party, setParty] = useState<string[]>([]);

    const selectedDungeon = DUNGEONS.find(d => d.id === selectedDungeonId) || DUNGEONS[0];

    const hiredMercs = useMemo(() => knownMercenaries.filter(m => m.status === 'HIRED'), [knownMercenaries]);
    const currentExpedition = activeExpeditions.find(e => e.dungeonId === selectedDungeon.id);

    const isMercBusy = (mercId: string) => {
        return activeExpeditions.some(e => e.partyIds.includes(mercId));
    };

    const handleSelectDungeon = (id: string) => {
        setSelectedDungeonId(id);
        setParty([]); 
    };

    const toggleMercenary = (mercId: string) => {
        if (party.includes(mercId)) {
            setParty(prev => prev.filter(id => id !== mercId));
        } else {
            if (party.length < 4) {
                setParty(prev => [...prev, mercId]);
            }
        }
    };

    const handleStartExpedition = () => {
        if (party.length === 0 || !selectedDungeon) return;
        actions.startExpedition(selectedDungeon.id, party);
    };

    const handleClaim = (expId: string) => {
        actions.claimExpedition(expId);
    };

    const currentPartyPower = useMemo(() => {
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        return calculatePartyPower(selectedMercs);
    }, [party, knownMercenaries]);

    const canStart = useMemo(() => {
        if (!selectedDungeon) return false;
        if (party.length === 0) return false;
        if (currentPartyPower < selectedDungeon.requiredPower) return false;

        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        const hasEnergy = selectedMercs.every(m => (m.expeditionEnergy || 0) >= selectedDungeon.energyCost);

        return hasEnergy;
    }, [selectedDungeon, party, currentPartyPower, knownMercenaries]);

    const [timeLeft, setTimeLeft] = useState<string>('');
    const isComplete = currentExpedition?.status === 'COMPLETED';

    useEffect(() => {
        if (!currentExpedition) return;
        if (currentExpedition.status === 'COMPLETED') {
            setTimeLeft('00:00');
            return;
        }

        const interval = setInterval(() => {
            const now = Date.now();
            const end = currentExpedition.endTime;
            const diff = end - now;
            if (diff <= 0) setTimeLeft('00:00');
            else setTimeLeft(formatDuration(diff));
        }, 1000);

        return () => clearInterval(interval);
    }, [currentExpedition]);

    return (
        <div className="h-full w-full flex flex-col md:flex-row bg-stone-950 text-stone-200">

            {/* Sidebar: Dungeon List - Full width on small, 1/3 on md+ */}
            <div className="w-full md:w-1/3 min-w-0 md:min-w-[250px] h-[35%] md:h-full bg-stone-900 border-b md:border-b-0 md:border-r border-stone-800 flex flex-col shrink-0">
                <div className="p-3 md:p-4 border-b border-stone-800 flex items-center gap-2">
                    <MapIcon className="w-4 h-4 md:w-5 md:h-5 text-amber-500" />
                    <h2 className="font-bold font-serif tracking-wide text-amber-100 text-sm md:text-base">Expeditions</h2>
                </div>

                <div className="flex-1 overflow-y-auto p-2 space-y-2 custom-scrollbar">
                    {DUNGEONS.map(dungeon => {
                        const clears = dungeonClearCounts[dungeon.id] || 0;
                        const isUnlocked = dungeon.tier <= state.stats.tierLevel + 1; 
                        const activeExp = activeExpeditions.find(e => e.dungeonId === dungeon.id);

                        return (
                            <button
                                key={dungeon.id}
                                onClick={() => handleSelectDungeon(dungeon.id)}
                                disabled={!isUnlocked}
                                className={`w-full p-2.5 md:p-3 rounded-lg text-left transition-all border relative overflow-hidden group ${
                                    selectedDungeon.id === dungeon.id 
                                    ? 'bg-amber-900/20 border-amber-500' 
                                    : 'bg-stone-800 border-stone-700 hover:border-stone-500'
                                } ${!isUnlocked ? 'opacity-50 grayscale cursor-not-allowed' : ''}`}
                            >
                                <div className="flex justify-between items-start mb-1 relative z-10">
                                    <span className={`font-bold text-xs md:text-sm truncate pr-2 ${selectedDungeon.id === dungeon.id ? 'text-amber-400' : 'text-stone-300'}`}>
                                        {dungeon.name}
                                    </span>
                                    <span className="text-[9px] md:text-xs bg-stone-950 px-1 py-0.5 rounded text-stone-500 font-mono shrink-0">T{dungeon.tier}</span>
                                </div>

                                <div className="flex items-center gap-2 text-[10px] md:text-xs text-stone-500 relative z-10">
                                    <div className="flex items-center gap-1">
                                        <Sword className="w-2.5 h-2.5 md:w-3 md:h-3" /> {dungeon.requiredPower}
                                    </div>
                                    <div className="flex items-center gap-1">
                                        <Timer className="w-2.5 h-2.5 md:w-3 md:h-3" /> {dungeon.durationMinutes}m
                                    </div>
                                </div>

                                {activeExp && (
                                    <div className="absolute top-2 right-6 md:right-8 z-20">
                                         {activeExp.status === 'COMPLETED' ? (
                                             <CheckCircle className="w-3 h-3 md:w-4 md:h-4 text-emerald-500 animate-bounce" />
                                         ) : (
                                             <Timer className="w-3 h-3 md:w-4 md:h-4 text-amber-500 animate-pulse" />
                                         )}
                                    </div>
                                )}

                                {dungeon.bossUnlockReq && (
                                    <div className="mt-1.5 w-full bg-stone-950 h-1 rounded-full overflow-hidden relative z-10">
                                        <div 
                                            className="h-full bg-red-800" 
                                            style={{ width: `${Math.min(100, (clears / dungeon.bossUnlockReq) * 100)}%` }}
                                        ></div>
                                    </div>
                                )}
                            </button>
                        );
                    })}
                </div>
            </div>

            {/* Main Area - flex-1 and scrollable */}
            <div className="flex-1 flex flex-col relative overflow-hidden min-h-0">
                 <div className="absolute inset-0 opacity-20 pointer-events-none z-0">
                    <img src={getAssetUrl('dungeon_bg.png')} className="w-full h-full object-cover grayscale" />
                </div>

                <div className="flex-1 overflow-y-auto relative z-10 custom-scrollbar">
                    {currentExpedition ? (
                        <div className="min-h-full flex flex-col items-center justify-center p-6 md:p-8 text-center">
                            <div className="w-24 h-24 md:w-32 md:h-32 bg-stone-900 rounded-full border-4 border-stone-700 flex items-center justify-center mb-4 md:mb-6 shadow-2xl relative">
                                {isComplete ? (
                                    <CheckCircle className="w-12 h-12 md:w-16 md:h-16 text-emerald-500 animate-bounce" />
                                ) : (
                                    <Timer className="w-12 h-12 md:w-16 md:h-16 text-amber-500 animate-pulse" />
                                )}
                            </div>

                            <h2 className="text-xl md:text-3xl font-bold text-stone-200 mb-2">{selectedDungeon.name}</h2>
                            <div className="text-sm md:text-xl font-mono text-amber-500 mb-6 md:mb-8 bg-stone-900/80 px-4 py-2 rounded-lg border border-stone-800">
                                {isComplete ? "MISSION COMPLETE" : `Time Remaining: ${timeLeft}`}
                            </div>

                            {isComplete ? (
                                <button 
                                    onClick={() => handleClaim(currentExpedition.id)}
                                    className="px-6 md:px-8 py-2 md:py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-bold rounded-lg shadow-lg flex items-center gap-2 animate-in zoom-in"
                                >
                                    <Trophy className="w-4 h-4 md:w-5 md:h-5" />
                                    Claim Rewards
                                </button>
                            ) : (
                                <div className="flex gap-2">
                                    {currentExpedition.partyIds.map(id => {
                                        const merc = knownMercenaries.find(m => m.id === id);
                                        if(!merc) return null;
                                        return (
                                            <div key={id} className="w-10 h-10 md:w-12 md:h-12 rounded-full bg-stone-800 border-2 border-stone-600 flex items-center justify-center text-lg md:text-xl shadow-lg" title={merc.name}>
                                                {merc.icon}
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="p-4 md:p-6 space-y-6">
                            <div className="bg-stone-900/90 border border-stone-800 p-4 md:p-6 rounded-xl backdrop-blur-sm">
                                <div className="flex flex-col sm:flex-row justify-between items-start mb-4 gap-3">
                                    <div>
                                        <h1 className="text-xl md:text-3xl font-bold text-amber-500 font-serif">{selectedDungeon.name}</h1>
                                        <p className="text-stone-400 mt-1 max-w-lg text-xs md:text-sm">{selectedDungeon.description}</p>
                                    </div>
                                    <div className="text-left sm:text-right shrink-0">
                                        <div className="text-[10px] text-stone-500 uppercase font-bold tracking-widest mb-1">Recommended Power</div>
                                        <div className={`text-base md:text-2xl font-mono font-bold ${currentPartyPower >= selectedDungeon.requiredPower ? 'text-emerald-500' : 'text-red-500'}`}>
                                            {currentPartyPower} / {selectedDungeon.requiredPower}
                                        </div>
                                    </div>
                                </div>

                                <div className="flex flex-wrap gap-2 md:gap-4 text-[10px] md:text-sm font-bold text-stone-300">
                                    <div className="bg-stone-800 px-2 md:px-3 py-1 md:py-1.5 rounded flex items-center gap-1.5 md:gap-2">
                                        <Timer className="w-3 h-3 md:w-4 md:h-4 text-stone-500" /> {selectedDungeon.durationMinutes} Minutes
                                    </div>
                                    <div className="bg-stone-800 px-2 md:px-3 py-1 md:py-1.5 rounded flex items-center gap-1.5 md:gap-2">
                                        <Zap className="w-3 h-3 md:w-4 md:h-4 text-blue-400" /> -{selectedDungeon.energyCost} Energy / Merc
                                    </div>
                                </div>
                            </div>

                            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 md:gap-6">
                                <div className="space-y-3 md:space-y-4">
                                    <h3 className="font-bold text-stone-400 uppercase tracking-wider text-[10px] md:text-sm flex items-center gap-2">
                                        <User className="w-3 h-3 md:w-4 md:h-4" /> Expedition Party ({party.length}/4)
                                    </h3>
                                    <div className="grid grid-cols-2 gap-2 md:gap-3">
                                        {[0, 1, 2, 3].map(idx => {
                                            const mercId = party[idx];
                                            const merc = knownMercenaries.find(m => m.id === mercId);
                                            return (
                                                <div key={idx} className="h-16 md:h-24 bg-stone-900/50 border-2 border-dashed border-stone-700 rounded-xl flex items-center justify-center relative overflow-hidden group hover:border-stone-500 transition-colors">
                                                    {merc ? (
                                                        <button onClick={() => toggleMercenary(merc.id)} className="w-full h-full flex items-center gap-2 md:gap-3 px-2 md:px-3 bg-stone-800 border-none">
                                                            <div className="text-xl md:text-3xl">{merc.icon}</div>
                                                            <div className="text-left min-w-0">
                                                                <div className="font-bold text-stone-200 truncate text-[11px] md:text-base">{merc.name}</div>
                                                                <div className="text-[9px] md:text-xs text-stone-500 truncate">{merc.job} (Lv.{merc.level})</div>
                                                                <div className="text-[9px] md:text-xs text-amber-500 font-mono">Pow: {calculateMercenaryPower(merc)}</div>
                                                            </div>
                                                            <div className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                                                <XCircle className="w-3 h-3 md:w-4 md:h-4 text-red-500" />
                                                            </div>
                                                        </button>
                                                    ) : (
                                                        <span className="text-stone-600 text-[9px] md:text-xs font-mono uppercase">Empty Slot</span>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>

                                <div className="flex flex-col min-h-[300px] bg-stone-900/80 rounded-xl border border-stone-800 overflow-hidden">
                                    <div className="p-2 md:p-3 border-b border-stone-800 bg-stone-900">
                                        <h3 className="font-bold text-stone-400 uppercase tracking-wider text-[10px] md:text-sm">Available Mercenaries</h3>
                                    </div>
                                    <div className="overflow-y-auto p-2 space-y-2 flex-1 custom-scrollbar">
                                        {hiredMercs.length === 0 ? (
                                            <div className="p-4 text-center text-stone-500 italic text-xs">No available mercenaries.</div>
                                        ) : (
                                            hiredMercs.map(merc => {
                                                const isSelected = party.includes(merc.id);
                                                const isBusy = isMercBusy(merc.id);
                                                const power = calculateMercenaryPower(merc);
                                                const energy = merc.expeditionEnergy || 0;
                                                const hasEnoughEnergy = energy >= selectedDungeon.energyCost;

                                                return (
                                                    <button 
                                                        key={merc.id}
                                                        onClick={() => !isBusy && toggleMercenary(merc.id)}
                                                        disabled={isBusy}
                                                        className={`w-full flex items-center justify-between p-2 md:p-3 rounded-lg border transition-all ${
                                                            isSelected 
                                                            ? 'bg-amber-900/30 border-amber-600' 
                                                            : 'bg-stone-800 border-stone-700 hover:bg-stone-750'
                                                        } ${isBusy ? 'opacity-50 cursor-not-allowed' : ''}`}
                                                    >
                                                        <div className="flex items-center gap-2 md:gap-3">
                                                            <div className="text-xl md:text-2xl">{merc.icon}</div>
                                                            <div className="text-left">
                                                                <div className="font-bold text-stone-200 text-xs md:text-sm">{merc.name}</div>
                                                                <div className="flex items-center gap-2 text-[10px] md:text-xs">
                                                                    <span className="text-stone-500">{merc.job}</span>
                                                                    <span className="text-amber-500 font-mono">Pow: {power}</span>
                                                                </div>
                                                            </div>
                                                        </div>

                                                        <div className="flex flex-col items-end gap-1">
                                                            {isBusy ? (
                                                                <span className="text-[8px] md:text-[10px] bg-stone-950 text-stone-500 px-1.5 md:py-0.5 rounded uppercase">Deployed</span>
                                                            ) : (
                                                                <div className="flex items-center gap-1" title={`${energy}/100 Energy`}>
                                                                    <Zap className={`w-2.5 h-2.5 md:w-3 md:h-3 ${hasEnoughEnergy ? 'text-blue-400' : 'text-red-500'}`} />
                                                                    <div className="w-12 md:w-16 h-1 md:h-1.5 bg-stone-950 rounded-full overflow-hidden">
                                                                        <div 
                                                                            className={`h-full ${hasEnoughEnergy ? 'bg-blue-500' : 'bg-red-500'}`} 
                                                                            style={{ width: `${energy}%` }}
                                                                        ></div>
                                                                    </div>
                                                                </div>
                                                            )}
                                                        </div>
                                                    </button>
                                                );
                                            })
                                        )}
                                    </div>
                                </div>
                            </div>

                            <div className="pt-4 border-t border-stone-800 flex justify-end pb-8">
                                <button 
                                    onClick={handleStartExpedition}
                                    disabled={!canStart}
                                    className={`px-6 md:px-8 py-3 md:py-4 rounded-xl font-bold text-sm md:text-lg shadow-lg flex items-center gap-2 transition-all ${
                                        canStart 
                                        ? 'bg-amber-600 hover:bg-amber-500 text-white hover:scale-105' 
                                        : 'bg-stone-800 text-stone-500 cursor-not-allowed'
                                    }`}
                                >
                                    {canStart ? (
                                        <>
                                            <Sword className="w-4 h-4 md:w-5 md:h-5" /> Start Expedition
                                        </>
                                    ) : (
                                        <>
                                            <Lock className="w-4 h-4 md:w-5 md:h-5" /> 
                                            {party.length === 0 ? 'Select Party' : 'Requirements Not Met'}
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

