                                <div className="flex items-center gap-1.5 text-xs md:text-lg font-black text-stone-200 font-mono"><Timer className="w-3 h-3 md:w-4 md:h-4 text-stone-500" /> {selectedDungeon.durationMinutes}m</div>
                            </div>
