  const triggerEnergyHighlight = () => {
      dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: true } });
      setTimeout(() => {
          dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: false } });
      }, 3000);
  };

  // --- ACTIONS ---
  // 의존성 배열을 비워 액션 함수들이 절대 변하지 않도록 설정
  const actions = useMemo(() => ({
    repairItem: () => {
        if (stateRef.current.stats.energy < GAME_CONFIG.ENERGY_COST.REPAIR) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'REPAIR_WORK' });
    },
    rest: () => dispatch({ type: 'SLEEP' }),
    confirmSleep: () => dispatch({ type: 'CONFIRM_SLEEP' }),

    triggerEvent: (event: GameEvent) => dispatch({ type: 'TRIGGER_EVENT', payload: event }),
    handleEventOption: (action: () => void) => {
      action();
      dispatch({ type: 'CLOSE_EVENT' });
    },
    closeEvent: () => dispatch({ type: 'CLOSE_EVENT' }),

    saveGame: () => {
        const success = saveToStorage(stateRef.current);
        if (success) {
            dispatch({ type: 'TRIGGER_EVENT', payload: {
                id: 'NONE',
                title: "Game Saved",
                description: "Your progress has been recorded in the annals of history.",
                options: [{ label: "Continue", action: () => {} }]
            }});
        }
    },
    loadGame: (loadedState: GameState) => {
        dispatch({ type: 'LOAD_GAME', payload: loadedState });
    },

    startCrafting: (item: EquipmentItem) => {
        const masteryCount = stateRef.current.craftingMastery[item.id] || 0;
        const energyCost = getEnergyCost(item, masteryCount);
        if (stateRef.current.stats.energy < energyCost) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'START_CRAFTING', payload: { item } });
    },
    cancelCrafting: (item: EquipmentItem) => dispatch({ type: 'CANCEL_CRAFTING', payload: { item } }),
    finishCrafting: (item: EquipmentItem, quality: number, bonus?: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality, bonus } }),
    craftItem: (item: EquipmentItem, quality: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality } }),
    dismissCraftingResult: () => dispatch({ type: 'DISMISS_CRAFTING_RESULT' }),

    buyItems: (items: { id: string; count: number }[], totalCost: number) => dispatch({ type: 'BUY_MARKET_ITEMS', payload: { items, totalCost } }),
    sellItem: (itemId: string, count: number, price: number, equipmentInstanceId?: string, customer?: Mercenary) =>
        dispatch({ type: 'SELL_ITEM', payload: { itemId, count, price, equipmentInstanceId, customer } }),
    toggleShop: () => {
        if (!stateRef.current.forge.isShopOpen && stateRef.current.stats.energy < GAME_CONFIG.ENERGY_COST.OPEN_SHOP) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'TOGGLE_SHOP' });
    },
    addMercenary: (merc: Mercenary) => dispatch({ type: 'ADD_KNOWN_MERCENARY', payload: merc }),

    consumeItem: (id: string, count: number) => dispatch({ type: 'PAY_COST', payload: { items: [{ id, count }] } }),

    enqueueCustomer: (customer: ShopCustomer) => dispatch({ type: 'ENQUEUE_CUSTOMER', payload: customer }),
    nextCustomer: () => dispatch({ type: 'NEXT_CUSTOMER' }),
    dismissCustomer: () => dispatch({ type: 'DISMISS_CUSTOMER' }),

    setCrafting: (isCrafting: boolean) => dispatch({ type: 'SET_CRAFTING', payload: isCrafting }),
    updateForgeStatus: (temp: number) => dispatch({ type: 'UPDATE_FORGE_STATUS', payload: { temp } }),
    updateMercenaryStats: (mercenaryId: string, stats: PrimaryStats) => dispatch({ type: 'UPDATE_MERCENARY_STATS', payload: { mercenaryId, stats } }),
    toggleJournal: () => dispatch({ type: 'TOGGLE_JOURNAL' }),

    hireMercenary: (mercenaryId: string, cost: number) => dispatch({ type: 'HIRE_MERCENARY', payload: { mercenaryId, cost } }),
    fireMercenary: (mercenaryId: string) => dispatch({ type: 'FIRE_MERCENARY', payload: { mercenaryId } }),
    giveGift: (mercenaryId: string, itemId: string) => dispatch({ type: 'GIVE_GIFT', payload: { mercenaryId, itemId } }),

    startExpedition: (dungeonId: string, partyIds: string[]) => dispatch({ type: 'START_EXPEDITION', payload: { dungeonId, partyIds } }),
    completeExpedition: (expeditionId: string) => dispatch({ type: 'COMPLETE_EXPEDITION', payload: { expeditionId } }),
    claimExpedition: (expeditionId: string) => dispatch({ type: 'CLAIM_EXPEDITION', payload: { expeditionId } }),
    dismissDungeonResult: () => dispatch({ type: 'DISMISS_DUNGEON_RESULT' }),

    equipItem: (mercenaryId: string, inventoryItemId: string) => dispatch({ type: 'EQUIP_ITEM', payload: { mercenaryId, inventoryItemId } }),
    unequipItem: (mercenaryId: string, slot: EquipmentSlotType) => dispatch({ type: 'UNEQUIP_ITEM', payload: { mercenaryId, slot } }),

    useItem: (itemId: string) => dispatch({ type: 'USE_ITEM', payload: { itemId } }),
    allocateStat: (mercenaryId: string, stat: keyof PrimaryStats) => dispatch({ type: 'ALLOCATE_STAT', payload: { mercenaryId, stat } }),

    triggerEnergyHighlight
    // Fix: Added missing closing parenthesis to correctly terminate the useMemo callback
  }), []); 

  return (
    <GameContext.Provider value={{ state, actions }}>
      {children}
    </GameContext.Provider>
  );
};

export { GameContext };

import React, { useEffect, useRef, useState } from 'react';
import Phaser from 'phaser';
import { X, Scissors } from 'lucide-react';
import { getAssetUrl } from '../../../utils';

interface WorkbenchMinigameProps {
  onComplete: (score: number, bonus?: number) => void;
  onClose: () => void;
  difficulty?: number;
}

// Fix: Implemented the missing WorkbenchScene class to handle the workbench crafting minigame
class WorkbenchScene extends Phaser.Scene {
  private onComplete?: (score: number, bonus?: number) => void;
  private difficulty: number = 1;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
  }

  create() {
    const { width, height } = this.scale;

    // Simple visual layout
    this.add.rectangle(0, 0, width, height, 0x1c1917).setOrigin(0);

    this.add.text(width / 2, height / 2 - 60, 'WORKBENCH', {
      fontFamily: 'serif',
      fontSize: '42px',
      color: '#10b981',
      fontStyle: 'bold'
    }).setOrigin(0.5);

    this.add.text(width / 2, height / 2, 'Assembling delicate components...', {
      fontFamily: 'monospace',
      fontSize: '16px',
      color: '#94a3b8'
    }).setOrigin(0.5);

    // Interactive button to complete the minigame
    const btn = this.add.container(width / 2, height / 2 + 80);
    const bg = this.add.rectangle(0, 0, 260, 60, 0x065f46).setInteractive({ cursor: 'pointer' }).setStrokeStyle(2, 0x10b981);
    const txt = this.add.text(0, 0, 'FINISH ASSEMBLY', { fontSize: '18px', fontStyle: 'bold', color: '#ffffff' }).setOrigin(0.5);
    btn.add([bg, txt]);

    bg.on('pointerdown', () => {
      // Calculate a randomized score based on difficulty (placeholder logic)
      const baseScore = 95 - (this.difficulty * 2);
      const variance = Math.floor(Math.random() * 15);
      const finalScore = Math.min(115, baseScore + variance);

      this.onComplete?.(finalScore, this.difficulty > 2 ? 5 : 0); 
    });

    bg.on('pointerover', () => bg.setFillStyle(0x059669));
    bg.on('pointerout', () => bg.setFillStyle(0x065f46));
  }
}

const WorkbenchMinigame: React.FC<WorkbenchMinigameProps> = ({ onComplete, onClose, difficulty = 1 }) => {
  const gameRef = useRef<Phaser.Game | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isReady, setIsReady] = useState(false);

  const onCompleteRef = useRef(onComplete);
  useEffect(() => { onCompleteRef.current = onComplete; }, [onComplete]);

  useEffect(() => {
    const checkSize = () => {
        if (containerRef.current && containerRef.current.clientWidth > 0 && containerRef.current.clientHeight > 0) setIsReady(true);
        else requestAnimationFrame(checkSize);
    };
    checkSize();
  }, []);

  useEffect(() => {
    if (!isReady || !containerRef.current) return;
    const config: Phaser.Types.Core.GameConfig = {
      type: Phaser.AUTO, parent: containerRef.current,
      width: containerRef.current.clientWidth, height: containerRef.current.clientHeight,
      backgroundColor: '#0c0a09', scene: [WorkbenchScene],
      scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
    };
    const game = new Phaser.Game(config);
    gameRef.current = game;

    // onCompleteRef.current를 호출하는 래퍼 함수 전달
    game.scene.start('WorkbenchScene', { 
        onComplete: (score: number, bonus?: number) => onCompleteRef.current(score, bonus), 
        difficulty 
    });

    const resizeObserver = new ResizeObserver((entries) => {
        for (let entry of entries) {
            const { width, height } = entry.contentRect;
            if (game && game.scale && width > 0 && height > 0) {
                game.scale.resize(width, height);
            }
        }
    });
    if (containerRef.current) resizeObserver.observe(containerRef.current);

    return () => { 
        resizeObserver.disconnect();
        if (gameRef.current) gameRef.current.destroy(true); 
    };
  }, [isReady, difficulty]); 

  return (
    <div className="absolute inset-0 z-50 flex flex-col bg-stone-950 animate-in fade-in duration-300 overflow-hidden">
        <div className="w-full h-10 md:h-14 shrink-0 bg-stone-900 border-b border-stone-800 flex items-center justify-between px-4 z-10 shadow-lg">
            <div className="flex items-center gap-2">
                <Scissors className="w-4 h-4 text-emerald-400" />
                <span className="text-stone-200 font-bold text-xs md:text-sm tracking-wide">Workbench</span>
            </div>
            <button onClick={onClose} className="flex items-center gap-1 px-3 py-1 bg-stone-800 hover:bg-red-900/20 text-stone-400 hover:text-red-400 rounded border border-stone-700 transition-all text-[10px] font-bold">
                <X className="w-3 h-3" /> CANCEL
            </button>
        </div>
        <div className="flex-1 w-full relative flex items-center justify-center bg-[#1c1917] overflow-hidden">
            <div 
              ref={containerRef} 
              style={{ width: '100%', height: '100dvh' }}
              className="overflow-hidden" 
            />
        </div>
    </div>
  );
};

export default WorkbenchMinigame;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public anims!: Phaser.Animations.AnimationManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;
  private virtualW = 0;
  private virtualH = 0;
  private isPortrait = false;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  private toVirtual(sx: number, sy: number) {
    if (!this.isPortrait) return { x: sx, y: sy };
    return { x: sy, y: this.virtualH - sx };
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      const virtual = this.toVirtual(pointer.x, pointer.y);

      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(virtual.x, virtual.y); return; }

      if (this.isPointerInHitArea(virtual.x, virtual.y) || Phaser.Math.Distance.Between(virtual.x, virtual.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(virtual.x, virtual.y);
      } else {
          this.handleMiss(virtual.x, virtual.y);
      }
    }, this);
  }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
    } else {
        this.cameras.main.shake(50, 0.005);
        this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, vx, vy);
    }
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished) return;
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
        this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, vx, vy);
        return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff);
      this.combo++;
      this.perfectCount++;
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
          this.showFeedback('QUALITY UP!', 0xfbbf24, 1.3, this.hitX, this.hitY - 60);
      }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', vx, vy); 
      this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff);
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', vx, vy);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else {
      this.handleMiss(vx, vy);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private isBellowsClick(objs: any[]) { return objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c)); }
  private isHeatUpClick(objs: any[]) { return objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c)); }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const screenW = gameSize?.width ?? this.scale.gameSize.width;
    const screenH = gameSize?.height ?? this.scale.gameSize.height;

    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    this.centerX = this.virtualW / 2;
    this.centerY = this.virtualH / 2;
    const w = this.virtualW;
    const h = this.virtualH;
    const isCompact = h < 450;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);
    this.startRadius = Phaser.Math.Clamp(h * 0.35, 120, 240);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage) {
      const targetWidth = w * (isCompact ? 1.2 : 1.4);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.4; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;

    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(isCompact);
    if (this.isPlaying) this.resetRing(); 
  }

  private repositionUIElements(isCompact: boolean) {
    const w = this.virtualW;
    const h = this.virtualH;

    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, 55).setFontSize(isCompact ? '14px' : '16px');

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100; 
    const barH = isCompact ? 120 : 200;

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tFrame.setPosition(sideX, sideY).setSize(28, barH + 10);
    tBg.setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20).setFontSize(isCompact ? '12px' : '14px');

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45).setScale(isCompact ? 0.8 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap).setScale(isCompact ? 0.8 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180)).setFontSize(isCompact ? '18px' : '24px');
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x ?? this.hitX, y ?? this.hitY);
    this.updateProgressBar();
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;

    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));

    if (this.isPlaying) {
      if (this.temperature <= 0) {
        this.targetRing.clear();
        this.approachRing.clear();
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
      } else {
        if (this.infoText.visible && this.infoText.text.includes('COLD')) {
            this.infoText.setVisible(false);
            this.resetRing();
        }
        this.handleRingLogic(delta);
      }
    }

    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
        this.isReadyToStart = false;
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6');
    }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);

    let barColor = 0xeab308; 
    if (ratio < 0.4) barColor = 0x3b82f6; else if (ratio > 0.7) barColor = 0xef4444;
    this.tempBar.setFillStyle(barColor);

    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    this.setBladeStage(stage);

    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
          this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
          this.bladeContainer.add(this.bladeImage);
      } else if (this.bladeImage.texture.key !== key) {
          this.bladeImage.setTexture(key);
          this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) {
        this.combo = 0;
        this.resetRing();
    }
  }

  private resetRing() {
    this.targetRing.clear();
    this.approachRing.clear();

    if (this.temperature <= 0) return;

    this.currentRadius = this.startRadius;
    this.ringTimer = 0;
    const w = this.hammerHitArea.width;
    const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
        this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    this.root.add(emitter);
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Arial Black', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { 
        this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); 
        this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700 }); 
    }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.virtualW, this.virtualH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg);
    this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  private pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.bellowsSprite.play('bellows_pump');
    if (this.temperature >= 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (this.temperature > 0) {
          if (!this.isPlaying && !this.isReadyToStart) {
              this.isReadyToStart = true;
              this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
          }
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0 && this.onHeatUpRequest) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
        this.isReadyToStart = true;
        this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private refreshHeatUpButton() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`);
    if (bg) bg.setStrokeStyle(3, this.charcoalCount > 0 ? 0xea580c : 0x292524);
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public anims!: Phaser.Animations.AnimationManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;

  // Cooldown for pumping to prevent ultra-spamming while allowing fast rapid fire
  private lastPumpTime: number = 0;
  private pumpCooldown: number = 100; 

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;
  private virtualW = 0;
  private virtualH = 0;
  private isPortrait = false;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.lastPumpTime = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  private toVirtual(sx: number, sy: number) {
    if (!this.isPortrait) return { x: sx, y: sy };
    return { x: sy, y: this.virtualH - sx };
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      const virtual = this.toVirtual(pointer.x, pointer.y);

      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(virtual.x, virtual.y); return; }

      if (this.isPointerInHitArea(virtual.x, virtual.y) || Phaser.Math.Distance.Between(virtual.x, virtual.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(virtual.x, virtual.y);
      } else {
          this.handleMiss(virtual.x, virtual.y);
      }
    }, this);
  }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
    } else {
        this.cameras.main.shake(50, 0.005);
        this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, vx, vy);
    }
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished) return;
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
        this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, vx, vy);
        return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff);
      this.combo++;
      this.perfectCount++;
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
          this.showFeedback('QUALITY UP!', 0xfbbf24, 1.3, this.hitX, this.hitY - 60);
      }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', vx, vy); 
      this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff);
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', vx, vy);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else {
      this.handleMiss(vx, vy);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private isBellowsClick(objs: any[]) { 
    return objs.includes(this.bellowsContainer) || (this.bellowsContainer && this.bellowsContainer.list.some(c => objs.includes(c))); 
  }
  private isHeatUpClick(objs: any[]) { 
    return objs.includes(this.heatUpBtnContainer) || (this.heatUpBtnContainer && this.heatUpBtnContainer.list.some(c => objs.includes(c))); 
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const screenW = gameSize?.width ?? this.scale.gameSize.width;
    const screenH = gameSize?.height ?? this.scale.gameSize.height;

    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    this.centerX = this.virtualW / 2;
    this.centerY = this.virtualH / 2;
    const w = this.virtualW;
    const h = this.virtualH;
    const isCompact = h < 450;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);
    this.startRadius = Phaser.Math.Clamp(h * 0.35, 120, 240);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage) {
      const targetWidth = w * (isCompact ? 1.2 : 1.4);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.4; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;

    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(isCompact);
    if (this.isPlaying) this.resetRing(); 
  }

  private repositionUIElements(isCompact: boolean) {
    const w = this.virtualW;
    const h = this.virtualH;

    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, 55).setFontSize(isCompact ? '14px' : '16px');

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100; 
    const barH = isCompact ? 120 : 200;

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tFrame.setPosition(sideX, sideY).setSize(28, barH + 10);
    tBg.setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20).setFontSize(isCompact ? '12px' : '14px');

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45).setScale(isCompact ? 0.8 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap).setScale(isCompact ? 0.8 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180)).setFontSize(isCompact ? '18px' : '24px');
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x ?? this.hitX, y ?? this.hitY);
    this.updateProgressBar();
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;

    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));

    if (this.isPlaying) {
      if (this.temperature <= 0) {
        this.targetRing.clear();
        this.approachRing.clear();
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
      } else {
        if (this.infoText.visible && this.infoText.text.includes('COLD')) {
            this.infoText.setVisible(false);
            this.resetRing();
        }
        this.handleRingLogic(delta);
      }
    }

    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
        this.isReadyToStart = false;
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6');
    }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);

    let barColor = 0xeab308; 
    if (ratio < 0.4) barColor = 0x3b82f6; else if (ratio > 0.7) barColor = 0xef4444;
    this.tempBar.setFillStyle(barColor);

    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    this.setBladeStage(stage);

    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
          this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
          this.bladeContainer.add(this.bladeImage);
      } else if (this.bladeImage.texture.key !== key) {
          this.bladeImage.setTexture(key);
          this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) {
        this.combo = 0;
        this.resetRing();
    }
  }

  private resetRing() {
    this.targetRing.clear();
    this.approachRing.clear();

    if (this.temperature <= 0) return;

    this.currentRadius = this.startRadius;
    this.ringTimer = 0;
    const w = this.hammerHitArea.width;
    const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
        this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    this.root.add(emitter);
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Arial Black', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { 
        this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); 
        this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700 }); 
    }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.virtualW, this.virtualH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg);
    this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  private pumpBellows() {
    const now = this.time.now;
    // Short cooldown (100ms) to allow rapid fire but prevent logic overlapping in the same frame
    if (now - this.lastPumpTime < this.pumpCooldown) return;
    this.lastPumpTime = now;

    // Play animation, starting from beginning if already playing to show immediate reaction
    if (this.bellowsSprite) {
        this.bellowsSprite.play('bellows_pump', true);
    }

    if (this.temperature >= 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (this.temperature > 0) {
          if (!this.isPlaying && !this.isReadyToStart) {
              this.isReadyToStart = true;
              this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
          }
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0 && this.onHeatUpRequest) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
        this.isReadyToStart = true;
        this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private refreshHeatUpButton() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`);
    if (bg) bg.setStrokeStyle(3, this.charcoalCount > 0 ? 0xea580c : 0x292524);
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public anims!: Phaser.Animations.AnimationManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;

  private lastPumpTime: number = 0;
  private pumpCooldown: number = 100; 

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;
  private virtualW = 0;
  private virtualH = 0;
  private isPortrait = false;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = (20 + (this.temperature / 100) * 1480) > 400;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.lastPumpTime = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  private toVirtual(sx: number, sy: number) {
    if (!this.isPortrait) return { x: sx, y: sy };
    return { x: sy, y: this.virtualH - sx };
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      const virtual = this.toVirtual(pointer.x, pointer.y);

      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(virtual.x, virtual.y); return; }

      if (this.isPointerInHitArea(virtual.x, virtual.y) || Phaser.Math.Distance.Between(virtual.x, virtual.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(virtual.x, virtual.y);
      } else {
          this.handleMiss(virtual.x, virtual.y);
      }
    }, this);
  }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
    } else {
        const realTemp = 20 + (this.temperature / 100) * 1480;
        this.cameras.main.shake(50, 0.005);
        this.showFeedback(realTemp <= 20 ? 'FORGE IS COLD!' : 'TOO COLD TO START!', 0x3b82f6, 1.0, vx, vy);
    }
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished) return;
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
        this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, vx, vy);
        return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff);
      this.combo++;
      this.perfectCount++;
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
          this.showFeedback('QUALITY UP!', 0xfbbf24, 1.3, this.hitX, this.hitY - 60);
      }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', vx, vy); 
      this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff);
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', vx, vy);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else {
      this.handleMiss(vx, vy);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private isBellowsClick(objs: any[]) { 
    return objs.includes(this.bellowsContainer) || (this.bellowsContainer && this.bellowsContainer.list.some(c => objs.includes(c))); 
  }
  private isHeatUpClick(objs: any[]) { 
    return objs.includes(this.heatUpBtnContainer) || (this.heatUpBtnContainer && this.heatUpBtnContainer.list.some(c => objs.includes(c))); 
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const screenW = gameSize?.width ?? this.scale.gameSize.width;
    const screenH = gameSize?.height ?? this.scale.gameSize.height;

    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    this.centerX = this.virtualW / 2;
    this.centerY = this.virtualH / 2;
    const w = this.virtualW;
    const h = this.virtualH;
    const isCompact = h < 450;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);
    this.startRadius = Phaser.Math.Clamp(h * 0.35, 120, 240);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage) {
      const targetWidth = w * (isCompact ? 1.2 : 1.4);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.4; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;

    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(isCompact);
    if (this.isPlaying) this.resetRing(); 
  }

  private repositionUIElements(isCompact: boolean) {
    const w = this.virtualW;
    const h = this.virtualH;

    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, 55).setFontSize(isCompact ? '14px' : '16px');

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100; 
    const barH = isCompact ? 120 : 200;

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tFrame.setPosition(sideX, sideY).setSize(28, barH + 10);
    tBg.setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20).setFontSize(isCompact ? '12px' : '14px');

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45).setScale(isCompact ? 0.8 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap).setScale(isCompact ? 0.8 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180)).setFontSize(isCompact ? '18px' : '24px');
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x ?? this.hitX, y ?? this.hitY);
    this.updateProgressBar();
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;

    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));

    if (this.isPlaying) {
      if (this.temperature <= 0) {
        this.targetRing.clear();
        this.approachRing.clear();
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
      } else {
        if (this.infoText.visible && (this.infoText.text.includes('COLD') || this.infoText.text.includes('FUEL'))) {
            this.infoText.setVisible(false);
            this.resetRing();
        }
        this.handleRingLogic(delta);
      }
    }

    this.refreshVisuals();
    if (!this.isPlaying) {
        const realTemp = 20 + (this.temperature / 100) * 1480;
        if (this.isReadyToStart && realTemp <= 400) {
            this.isReadyToStart = false;
            this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
        } else if (!this.isReadyToStart && realTemp > 400) {
            this.isReadyToStart = true;
            this.infoText.setText('TOUCH TO START').setColor('#fbbf24').setVisible(true);
        }
    }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    const realTemp = Math.floor(20 + ratio * 1480);
    this.tempValueText.setText(`${realTemp}°C`);

    // Smooth Color Interpolation: Blue(Cold) -> Amber(Normal) -> Red(Hot)
    let color: number;
    if (ratio < 0.5) {
        // Interpolate between Blue (0x3b82f6) and Amber (0xfbbf24)
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 59, g: 130, b: 246 }), // Blue
            Phaser.Display.Color.ObjectToColor({ r: 251, g: 191, b: 36 }),  // Amber
            0.5,
            ratio * 2
        ).color;
    } else {
        // Interpolate between Amber (0xfbbf24) and Red (0xef4444)
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 251, g: 191, b: 36 }),  // Amber
            Phaser.Display.Color.ObjectToColor({ r: 239, g: 68, b: 68 }),   // Red
            0.5,
            (ratio - 0.5) * 2
        ).color;
    }
    this.tempBar.setFillStyle(color);

    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    this.setBladeStage(stage);

    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
          this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
          this.bladeContainer.add(this.bladeImage);
      } else if (this.bladeImage.texture.key !== key) {
          this.bladeImage.setTexture(key);
          this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) {
        this.combo = 0;
        this.resetRing();
    }
  }

  private resetRing() {
    this.targetRing.clear();
    this.approachRing.clear();

    if (this.temperature <= 0) return;

    this.currentRadius = this.startRadius;
    this.ringTimer = 0;
    const w = this.hammerHitArea.width;
    const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
        this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    this.root.add(emitter);
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Arial Black', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { 
        this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); 
        this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700 }); 
    }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.virtualW, this.virtualH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg);
    this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  private pumpBellows() {
    const now = this.time.now;
    if (now - this.lastPumpTime < this.pumpCooldown) return;
    this.lastPumpTime = now;

    if (this.bellowsSprite) {
        this.bellowsSprite.play('bellows_pump', true);
    }

    // Restriction: Cannot pump if real temperature is <= 400°C
    const realTemp = 20 + (this.temperature / 100) * 1480;
    if (realTemp <= 400) {
        // Small feedback to indicate bellows are useless when fire is dying
        this.showFeedback('TOO COLD!', 0x3b82f6, 0.8, this.bellowsContainer.x, this.bellowsContainer.y - 40);
        return;
    }

    if (this.temperature >= 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (this.temperature > 0) {
          if (!this.isPlaying && !this.isReadyToStart) {
              const checkTemp = 20 + (this.temperature / 100) * 1480;
              if (checkTemp > 400) {
                  this.isReadyToStart = true;
                  this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
              }
          }
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0 && this.onHeatUpRequest) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    const realTemp = 20 + (this.temperature / 100) * 1480;
    if (!this.isPlaying && realTemp > 400) {
        this.isReadyToStart = true;
        this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private refreshHeatUpButton() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`);
    if (bg) bg.setStrokeStyle(3, this.charcoalCount > 0 ? 0xea580c : 0x292524);
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public anims!: Phaser.Animations.AnimationManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;

  private lastPumpTime: number = 0;
  private pumpCooldown: number = 100; 

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;
  private virtualW = 0;
  private virtualH = 0;
  private isPortrait = false;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = (20 + (this.temperature / 100) * 1480) > 400;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.lastPumpTime = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  private toVirtual(sx: number, sy: number) {
    if (!this.isPortrait) return { x: sx, y: sy };
    return { x: sy, y: this.virtualH - sx };
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      const virtual = this.toVirtual(pointer.x, pointer.y);

      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(virtual.x, virtual.y); return; }

      if (this.isPointerInHitArea(virtual.x, virtual.y) || Phaser.Math.Distance.Between(virtual.x, virtual.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(virtual.x, virtual.y);
      } else {
          this.handleMiss(virtual.x, virtual.y);
      }
    }, this);
  }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
    } else {
        const realTemp = 20 + (this.temperature / 100) * 1480;
        this.cameras.main.shake(50, 0.005);
        this.highlightHeatUpBtn();
    }
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished) return;
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
        this.highlightHeatUpBtn();
        return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff);
      this.combo++;
      this.perfectCount++;
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
          this.showFeedback('QUALITY UP!', 0xfbbf24, 1.3, this.hitX, this.hitY - 60);
      }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', vx, vy); 
      this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff);
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', vx, vy);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else {
      this.handleMiss(vx, vy);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private isBellowsClick(objs: any[]) { 
    return objs.includes(this.bellowsContainer) || (this.bellowsContainer && this.bellowsContainer.list.some(c => objs.includes(c))); 
  }
  private isHeatUpClick(objs: any[]) { 
    return objs.includes(this.heatUpBtnContainer) || (this.heatUpBtnContainer && this.heatUpBtnContainer.list.some(c => objs.includes(c))); 
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const screenW = gameSize?.width ?? this.scale.gameSize.width;
    const screenH = gameSize?.height ?? this.scale.gameSize.height;

    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    this.centerX = this.virtualW / 2;
    this.centerY = this.virtualH / 2;
    const w = this.virtualW;
    const h = this.virtualH;
    const isCompact = h < 450;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);
    this.startRadius = Phaser.Math.Clamp(h * 0.35, 120, 240);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage) {
      const targetWidth = w * (isCompact ? 1.2 : 1.4);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.4; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;

    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(isCompact);
    if (this.isPlaying) this.resetRing(); 
  }

  private repositionUIElements(isCompact: boolean) {
    const w = this.virtualW;
    const h = this.virtualH;

    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, 55).setFontSize(isCompact ? '14px' : '16px');

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100; 
    const barH = isCompact ? 120 : 200;

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tFrame.setPosition(sideX, sideY).setSize(28, barH + 10);
    tBg.setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20).setFontSize(isCompact ? '12px' : '14px');

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45).setScale(isCompact ? 0.8 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap).setScale(isCompact ? 0.8 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180)).setFontSize(isCompact ? '18px' : '24px');
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x ?? this.hitX, y ?? this.hitY);
    this.updateProgressBar();
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;

    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));

    if (this.isPlaying) {
      if (this.temperature <= 0) {
        this.targetRing.clear();
        this.approachRing.clear();
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
      } else {
        if (this.infoText.visible && (this.infoText.text.includes('COLD') || this.infoText.text.includes('FUEL'))) {
            this.infoText.setVisible(false);
            this.resetRing();
        }
        this.handleRingLogic(delta);
      }
    }

    this.refreshVisuals();
    if (!this.isPlaying) {
        const realTemp = 20 + (this.temperature / 100) * 1480;
        if (this.isReadyToStart && realTemp <= 400) {
            this.isReadyToStart = false;
            this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
        } else if (!this.isReadyToStart && realTemp > 400) {
            this.isReadyToStart = true;
            this.infoText.setText('TOUCH TO START').setColor('#fbbf24').setVisible(true);
        }
    }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    const realTemp = Math.floor(20 + ratio * 1480);
    this.tempValueText.setText(`${realTemp}°C`);

    // --- Smooth Color Interpolation: Multi-Stage Heat Ramp ---
    // Realistic forging colors: Cold -> Dark Red -> Bright Red -> Yellow -> White
    let color: number;
    if (ratio < 0.25) {
        // Stage 1: Cold (Blue 0x3b82f6) -> Low Heat (Dark Red 0x7f1d1d)
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 59, g: 130, b: 246 }), // Blue
            Phaser.Display.Color.ObjectToColor({ r: 127, g: 29, b: 29 }),  // Dark Red
            100,
            (ratio / 0.25) * 100
        ).color;
    } else if (ratio < 0.60) {
        // Stage 2: Low Heat -> Glowing Red (Bright Red 0xef4444)
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 127, g: 29, b: 29 }),  // Dark Red
            Phaser.Display.Color.ObjectToColor({ r: 239, g: 68, b: 68 }),  // Bright Red
            100,
            ((ratio - 0.25) / 0.35) * 100
        ).color;
    } else if (ratio < 0.85) {
        // Stage 3: Glowing Red -> Forging Heat (Bright Amber/Yellow 0xfbbf24)
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 239, g: 68, b: 68 }),  // Bright Red
            Phaser.Display.Color.ObjectToColor({ r: 251, g: 191, b: 36 }), // Amber
            100,
            ((ratio - 0.60) / 0.25) * 100
        ).color;
    } else {
        // Stage 4: Forging Heat -> Incandescent Heat (Pale Yellow/White 0xffffcc)
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 251, g: 191, b: 36 }), // Amber
            Phaser.Display.Color.ObjectToColor({ r: 255, g: 255, b: 204 }), // Pale Yellow
            100,
            ((ratio - 0.85) / 0.15) * 100
        ).color;
    }

    this.tempBar.setFillStyle(color);

    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    this.setBladeStage(stage);

    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
          this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
          this.bladeContainer.add(this.bladeImage);
      } else if (this.bladeImage.texture.key !== key) {
          this.bladeImage.setTexture(key);
          this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) {
        this.combo = 0;
        this.resetRing();
    }
  }

  private resetRing() {
    this.targetRing.clear();
    this.approachRing.clear();

    if (this.temperature <= 0) return;

    this.currentRadius = this.startRadius;
    this.ringTimer = 0;
    const w = this.hammerHitArea.width;
    const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
        this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    this.root.add(emitter);
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Arial Black', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { 
        this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); 
        this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700 }); 
    }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.virtualW, this.virtualH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg);
    this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  private highlightHeatUpBtn() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    if (!bg) return;

    // Kill existing highlight tweens to avoid stack
    this.tweens.killTweensOf(this.heatUpBtnContainer);

    this.tweens.add({
        targets: this.heatUpBtnContainer,
        scale: 1.2,
        duration: 200,
        yoyo: true,
        ease: 'Cubic.easeOut',
        onStart: () => {
            bg.setStrokeStyle(4, 0xffaa00);
        },
        onComplete: () => {
            this.refreshHeatUpButton();
        }
    });
  }

  private pumpBellows() {
    const now = this.time.now;
    if (now - this.lastPumpTime < this.pumpCooldown) return;
    this.lastPumpTime = now;

    if (this.bellowsSprite) {
        this.bellowsSprite.play('bellows_pump', true);
    }

    // Restriction: Cannot pump if real temperature is <= 400°C
    const realTemp = 20 + (this.temperature / 100) * 1480;
    if (realTemp <= 400) {
        this.highlightHeatUpBtn();
        return;
    }

    if (this.temperature >= 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (this.temperature > 0) {
          if (!this.isPlaying && !this.isReadyToStart) {
              const checkTemp = 20 + (this.temperature / 100) * 1480;
              if (checkTemp > 400) {
                  this.isReadyToStart = true;
                  this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
              }
          }
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0 && this.onHeatUpRequest) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    const realTemp = 20 + (this.temperature / 100) * 1480;
    if (!this.isPlaying && realTemp > 400) {
        this.isReadyToStart = true;
        this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private refreshHeatUpButton() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`);
    if (bg) bg.setStrokeStyle(3, this.charcoalCount > 0 ? 0xea580c : 0x292524);
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public anims!: Phaser.Animations.AnimationManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;

  private lastPumpTime: number = 0;
  private pumpCooldown: number = 100; 

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;
  private virtualW = 0;
  private virtualH = 0;
  private isPortrait = false;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = (20 + (this.temperature / 100) * 1480) > 400;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.lastPumpTime = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  private toVirtual(sx: number, sy: number) {
    if (!this.isPortrait) return { x: sx, y: sy };
    return { x: sy, y: this.virtualH - sx };
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      const virtual = this.toVirtual(pointer.x, pointer.y);

      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(virtual.x, virtual.y); return; }

      if (this.isPointerInHitArea(virtual.x, virtual.y) || Phaser.Math.Distance.Between(virtual.x, virtual.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(virtual.x, virtual.y);
      } else {
          this.handleMiss(virtual.x, virtual.y);
      }
    }, this);
  }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
    } else {
        this.cameras.main.shake(50, 0.005);
        this.highlightHeatUpBtn();
    }
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished) return;
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
        this.highlightHeatUpBtn();
        return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff);
      this.combo++;
      this.perfectCount++;
      // Silent Quality Up during perfect streaks
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
      }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', vx, vy); 
      this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff);
      this.combo = 0;
      this.perfectCount = 0; // Break streak
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', vx, vy);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else {
      this.handleMiss(vx, vy);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private isBellowsClick(objs: any[]) { 
    return objs.includes(this.bellowsContainer) || (this.bellowsContainer && this.bellowsContainer.list.some(c => objs.includes(c))); 
  }
  private isHeatUpClick(objs: any[]) { 
    return objs.includes(this.heatUpBtnContainer) || (this.heatUpBtnContainer && this.heatUpBtnContainer.list.some(c => objs.includes(c))); 
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const screenW = gameSize?.width ?? this.scale.gameSize.width;
    const screenH = gameSize?.height ?? this.scale.gameSize.height;

    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    this.centerX = this.virtualW / 2;
    this.centerY = this.virtualH / 2;
    const w = this.virtualW;
    const h = this.virtualH;
    const isCompact = h < 450;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);
    this.startRadius = Phaser.Math.Clamp(h * 0.35, 120, 240);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage) {
      const targetWidth = w * (isCompact ? 1.2 : 1.4);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.4; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;

    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(isCompact);
    if (this.isPlaying) this.resetRing(); 
  }

  private repositionUIElements(isCompact: boolean) {
    const w = this.virtualW;
    const h = this.virtualH;

    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, 55).setFontSize(isCompact ? '14px' : '16px');

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100; 
    const barH = isCompact ? 120 : 200;

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tFrame.setPosition(sideX, sideY).setSize(28, barH + 10);
    tBg.setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20).setFontSize(isCompact ? '12px' : '14px');

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45).setScale(isCompact ? 0.8 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap).setScale(isCompact ? 0.8 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180)).setFontSize(isCompact ? '18px' : '24px');
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.perfectCount = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x ?? this.hitX, y ?? this.hitY);
    this.updateProgressBar();
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;

    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));

    if (this.isPlaying) {
      if (this.temperature <= 0) {
        this.targetRing.clear();
        this.approachRing.clear();
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
      } else {
        if (this.infoText.visible && (this.infoText.text.includes('COLD') || this.infoText.text.includes('FUEL'))) {
            this.infoText.setVisible(false);
            this.resetRing();
        }
        this.handleRingLogic(delta);
      }
    }

    this.refreshVisuals();
    if (!this.isPlaying) {
        const realTemp = 20 + (this.temperature / 100) * 1480;
        if (this.isReadyToStart && realTemp <= 400) {
            this.isReadyToStart = false;
            this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
        } else if (!this.isReadyToStart && realTemp > 400) {
            this.isReadyToStart = true;
            this.infoText.setText('TOUCH TO START').setColor('#fbbf24').setVisible(true);
        }
    }
  }

  private refreshVisuals() {
    // Hide rank label during perfect sequences to satisfy requirement
    if (this.perfectCount > 0) {
        this.qualityText.setVisible(false);
    } else {
        this.qualityText.setVisible(true);
        this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    }

    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    const realTemp = Math.floor(20 + ratio * 1480);
    this.tempValueText.setText(`${realTemp}°C`);

    // --- Refined Smooth Multi-Stage Heat Ramp ---
    let color: number;
    if (ratio < 0.20) {
        // Stage 1: Cold (Blue) -> Dull Brown/Black
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 59, g: 130, b: 246 }), // Blue
            Phaser.Display.Color.ObjectToColor({ r: 28, g: 25, b: 23 }),   // Dark Stone
            100, (ratio / 0.20) * 100
        ).color;
    } else if (ratio < 0.45) {
        // Stage 2: Dull -> Dark Cherry (Threshold 400C is roughly 0.25)
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 28, g: 25, b: 23 }),
            Phaser.Display.Color.ObjectToColor({ r: 127, g: 29, b: 29 }),  // Dark Red
            100, ((ratio - 0.20) / 0.25) * 100
        ).color;
    } else if (ratio < 0.75) {
        // Stage 3: Dark Cherry -> Bright Orange
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 127, g: 29, b: 29 }),
            Phaser.Display.Color.ObjectToColor({ r: 249, g: 115, b: 22 }), // Orange
            100, ((ratio - 0.45) / 0.30) * 100
        ).color;
    } else {
        // Stage 4: Orange -> Incandescent White/Amber
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 249, g: 115, b: 22 }),
            Phaser.Display.Color.ObjectToColor({ r: 255, g: 253, b: 235 }), // Pale White-Yellow
            100, ((ratio - 0.75) / 0.25) * 100
        ).color;
    }

    this.tempBar.setFillStyle(color);

    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    this.setBladeStage(stage);

    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
          this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
          this.bladeContainer.add(this.bladeImage);
      } else if (this.bladeImage.texture.key !== key) {
          this.bladeImage.setTexture(key);
          this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) {
        this.combo = 0;
        this.perfectCount = 0;
        this.resetRing();
    }
  }

  private resetRing() {
    this.targetRing.clear();
    this.approachRing.clear();

    if (this.temperature <= 0) return;

    this.currentRadius = this.startRadius;
    this.ringTimer = 0;
    const w = this.hammerHitArea.width;
    const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
        this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    this.root.add(emitter);
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Arial Black', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { 
        this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); 
        this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700 }); 
    }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.virtualW, this.virtualH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg);
    this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  private highlightHeatUpBtn() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    if (!bg) return;

    this.tweens.killTweensOf(this.heatUpBtnContainer);

    this.tweens.add({
        targets: this.heatUpBtnContainer,
        scale: 1.2,
        duration: 200,
        yoyo: true,
        ease: 'Cubic.easeOut',
        onStart: () => {
            bg.setStrokeStyle(4, 0xffaa00);
        },
        onComplete: () => {
            this.refreshHeatUpButton();
        }
    });
  }

  private pumpBellows() {
    const now = this.time.now;
    if (now - this.lastPumpTime < this.pumpCooldown) return;
    this.lastPumpTime = now;

    if (this.bellowsSprite) {
        this.bellowsSprite.play('bellows_pump', true);
    }

    const realTemp = 20 + (this.temperature / 100) * 1480;
    if (realTemp <= 400) {
        this.highlightHeatUpBtn();
        return;
    }

    if (this.temperature >= 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (this.temperature > 0) {
          if (!this.isPlaying && !this.isReadyToStart) {
              const checkTemp = 20 + (this.temperature / 100) * 1480;
              if (checkTemp > 400) {
                  this.isReadyToStart = true;
                  this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
              }
          }
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0 && this.onHeatUpRequest) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    const realTemp = 20 + (this.temperature / 100) * 1480;
    if (!this.isPlaying && realTemp > 400) {
        this.isReadyToStart = true;
        this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private refreshHeatUpButton() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`);
    if (bg) bg.setStrokeStyle(3, this.charcoalCount > 0 ? 0xea580c : 0x292524);
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public anims!: Phaser.Animations.AnimationManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;

  private lastPumpTime: number = 0;
  private pumpCooldown: number = 100; 

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = (20 + (this.temperature / 100) * 1480) > 400;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.lastPumpTime = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(pointer.x, pointer.y); return; }

      if (this.isPointerInHitArea(pointer.x, pointer.y) || Phaser.Math.Distance.Between(pointer.x, pointer.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(pointer.x, pointer.y);
      } else {
          this.handleMiss(pointer.x, pointer.y);
      }
    }, this);
  }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
    } else {
        this.cameras.main.shake(50, 0.005);
        this.highlightHeatUpBtn();
    }
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished) return;
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
        this.highlightHeatUpBtn();
        return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff);
      this.combo++;
      this.perfectCount++;
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
      }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', vx, vy); 
      this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff);
      this.combo = 0;
      this.perfectCount = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', vx, vy);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else {
      this.handleMiss(vx, vy);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private isBellowsClick(objs: any[]) { 
    return objs.includes(this.bellowsContainer) || (this.bellowsContainer && this.bellowsContainer.list.some(c => objs.includes(c))); 
  }
  private isHeatUpClick(objs: any[]) { 
    return objs.includes(this.heatUpBtnContainer) || (this.heatUpBtnContainer && this.heatUpBtnContainer.list.some(c => objs.includes(c))); 
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.gameSize.width;
    const h = gameSize?.height ?? this.scale.gameSize.height;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isCompact = h < 450;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);
    this.startRadius = Phaser.Math.Clamp(h * 0.35, 120, 240);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage) {
      const targetWidth = w * (isCompact ? 1.2 : 1.4);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.4; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;

    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(w, h, isCompact);
    if (this.isPlaying) this.resetRing(); 
  }

  private repositionUIElements(w: number, h: number, isCompact: boolean) {
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, 55).setFontSize(isCompact ? '14px' : '16px');

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100; 
    const barH = isCompact ? 120 : 200;

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tFrame.setPosition(sideX, sideY).setSize(28, barH + 10);
    tBg.setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20).setFontSize(isCompact ? '12px' : '14px');

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45).setScale(isCompact ? 0.8 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap).setScale(isCompact ? 0.8 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180)).setFontSize(isCompact ? '18px' : '24px');
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.perfectCount = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x ?? this.hitX, y ?? this.hitY);
    this.updateProgressBar();
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    if (this.isPlaying) {
      if (this.temperature <= 0) {
        this.targetRing.clear(); this.approachRing.clear();
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
      } else {
        if (this.infoText.visible && (this.infoText.text.includes('COLD') || this.infoText.text.includes('FUEL'))) {
            this.infoText.setVisible(false); this.resetRing();
        }
        this.handleRingLogic(delta);
      }
    }
    this.refreshVisuals();
    if (!this.isPlaying) {
        const realTemp = 20 + (this.temperature / 100) * 1480;
        if (this.isReadyToStart && realTemp <= 400) {
            this.isReadyToStart = false;
            this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
        } else if (!this.isReadyToStart && realTemp > 400) {
            this.isReadyToStart = true;
            this.infoText.setText('TOUCH TO START').setColor('#fbbf24').setVisible(true);
        }
    }
  }

  private refreshVisuals() {
    if (this.perfectCount > 0) {
        this.qualityText.setVisible(false);
    } else {
        this.qualityText.setVisible(true);
        this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    }

    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    const realTemp = Math.floor(20 + ratio * 1480);
    this.tempValueText.setText(`${realTemp}°C`);

    let color: number;
    if (ratio < 0.20) {
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 59, g: 130, b: 246 }), 
            Phaser.Display.Color.ObjectToColor({ r: 28, g: 25, b: 23 }), 100, (ratio / 0.20) * 100
        ).color;
    } else if (ratio < 0.45) {
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 28, g: 25, b: 23 }),
            Phaser.Display.Color.ObjectToColor({ r: 127, g: 29, b: 29 }), 100, ((ratio - 0.20) / 0.25) * 100
        ).color;
    } else if (ratio < 0.75) {
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 127, g: 29, b: 29 }),
            Phaser.Display.Color.ObjectToColor({ r: 249, g: 115, b: 22 }), 100, ((ratio - 0.45) / 0.30) * 100
        ).color;
    } else {
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 249, g: 115, b: 22 }),
            Phaser.Display.Color.ObjectToColor({ r: 255, g: 253, b: 235 }), 100, ((ratio - 0.75) / 0.25) * 100
        ).color;
    }
    this.tempBar.setFillStyle(color);

    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    this.setBladeStage(stage);
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);

    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
          this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
          this.bladeContainer.add(this.bladeImage);
      } else if (this.bladeImage.texture.key !== key) {
          this.bladeImage.setTexture(key);
          this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) {
        this.combo = 0; this.perfectCount = 0; this.resetRing();
    }
  }

  private resetRing() {
    this.targetRing.clear(); this.approachRing.clear();
    if (this.temperature <= 0) return;
    this.currentRadius = this.startRadius;
    this.ringTimer = 0;
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35); const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
        this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    this.root.add(emitter); emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Arial Black', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { 
        this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); 
        this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700 }); 
    }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg); this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  private highlightHeatUpBtn() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    if (!bg) return;
    this.tweens.killTweensOf(this.heatUpBtnContainer);
    this.tweens.add({ targets: this.heatUpBtnContainer, scale: 1.2, duration: 200, yoyo: true, ease: 'Cubic.easeOut', onStart: () => { bg.setStrokeStyle(4, 0xffaa00); }, onComplete: () => { this.refreshHeatUpButton(); } });
  }

  private pumpBellows() {
    if (this.time.now - this.lastPumpTime < this.pumpCooldown) return;
    this.lastPumpTime = this.time.now;
    if (this.bellowsSprite) this.bellowsSprite.play('bellows_pump', true);
    const realTemp = 20 + (this.temperature / 100) * 1480;
    if (realTemp <= 400) { this.highlightHeatUpBtn(); return; }
    if (this.temperature >= 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (this.temperature > 0 && !this.isPlaying && !this.isReadyToStart) {
          if (20 + (this.temperature / 100) * 1480 > 400) {
              this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
          }
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0 && this.onHeatUpRequest) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying && 20 + (this.temperature / 100) * 1480 > 400) {
        this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private refreshHeatUpButton() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`);
    if (bg) bg.setStrokeStyle(3, this.charcoalCount > 0 ? 0xea580c : 0x292524);
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export default class IntroScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public game!: Phaser.Game;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private bgs: Phaser.GameObjects.Image[] = [];
  private dragon?: Phaser.GameObjects.Image;
  private narrativeTexts: Phaser.GameObjects.Text[] = [];
  private devText?: Phaser.GameObjects.Text;
  private skipHint?: Phaser.GameObjects.Text;
  private fireEmitter?: Phaser.GameObjects.Particles.ParticleEmitter;
  private breathOverlay?: Phaser.GameObjects.Rectangle;

  private root!: Phaser.GameObjects.Container;

  constructor() {
    super('IntroScene');
  }

  preload() {
    this.load.image('intro_bg', getAssetUrl('intro_bg_01.png'));
    this.load.image('intro_bg_02', getAssetUrl('intro_bg_02.png'));
    this.load.image('intro_bg_03', getAssetUrl('intro_bg_03.png'));
    this.load.image('intro_bg_04', getAssetUrl('intro_bg_04.png'));
    this.load.image('intro_bg_05', getAssetUrl('intro_bg_05.png'));
    this.load.image('intro_dragon', getAssetUrl('intro_dragon_02.png'));
  }

  private createNarrativeText(text: string, color: string = '#ef4444') {
    const t = this.add
      .text(0, 0, text, {
        fontFamily: 'serif', fontSize: '40px', color, align: 'center', fontStyle: 'italic', stroke: '#000000', strokeThickness: 4,
      })
      .setOrigin(0.5).setAlpha(0).setDepth(10);
    this.root.add(t);
    this.narrativeTexts.push(t);
    return t;
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);

    if (!this.textures.exists('intro_flame')) {
      const graphics = this.make.graphics({ x: 0, y: 0 });
      graphics.fillStyle(0xff5500, 1).fillCircle(16, 16, 16).generateTexture('intro_flame', 32, 32).destroy();
    }

    this.input.once('pointerdown', () => { this.game.events.emit('intro-complete'); });

    this.skipHint = this.add.text(0, 0, 'Touch anywhere to skip', {
      fontFamily: 'sans-serif', fontSize: '12px', color: '#57534e', fontStyle: 'bold'
    }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.skipHint);

    const keys = ['intro_bg', 'intro_bg_02', 'intro_bg_03', 'intro_bg_04', 'intro_bg_05'];
    keys.forEach(key => {
      const img = this.add.image(0, 0, key).setAlpha(0).setDepth(1);
      this.root.add(img); this.bgs.push(img);
    });

    this.dragon = this.add.image(0, 0, 'intro_dragon').setDepth(2).setVisible(false);
    this.root.add(this.dragon);

    this.devText = this.add.text(0, 0, "CRYINGDEV STUDIO\nPRESENTS", {
      fontFamily: 'serif', fontSize: '45px', color: '#a8a29e', align: 'center', fontStyle: 'bold'
    }).setOrigin(0.5).setAlpha(0).setDepth(10);
    this.root.add(this.devText);

    const n1 = this.createNarrativeText("FIASCO,\nA MASTER OF DISASTER...", '#ef4444');
    const n2 = this.createNarrativeText("EVERTHING WE LOVED IS LOST...", '#ef4444');
    const n3 = this.createNarrativeText("BUT THE HAMMER IS STILL HERE.", '#ef4444');
    const nDespair = this.createNarrativeText("NEVER FORGET...", '#ef4444');
    const nVengeance = this.createNarrativeText("AND FORGED A VENGEANCE.", '#f59e0b');

    this.breathOverlay = this.add.rectangle(0, 0, 10, 10, 0xff4400).setAlpha(0).setDepth(5).setBlendMode(Phaser.BlendModes.ADD);
    this.root.add(this.breathOverlay);

    this.fireEmitter = this.add.particles(0, 0, 'intro_flame', {
      speedY: { min: 1200, max: 2200 }, speedX: { min: -600, max: 600 }, scale: { start: 6, end: 15 },
      alpha: { start: 1, end: 0 }, lifespan: 1500, quantity: 40, blendMode: 'ADD', emitting: false
    });
    this.fireEmitter.setDepth(4); this.root.add(this.fireEmitter);

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
    this.startSequence(n1, n2, n3, nDespair, nVengeance);
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.gameSize.width;
    const h = gameSize?.height ?? this.scale.gameSize.height;
    const centerX = w / 2;
    const centerY = h / 2;

    this.cameras.main.setViewport(0, 0, w, h);
    const uiScale = Phaser.Math.Clamp(Math.min(w, h) / 720, 0.4, 1.2);

    this.bgs.forEach(img => {
      img.setPosition(centerX, centerY);
      img.setScale(Math.max(w / img.width, h / img.height));
    });

    if (this.dragon) {
      const dScale = Math.min((h * 0.55) / this.dragon.height, (w * 0.90) / this.dragon.width);
      this.dragon.setScale(dScale).setPosition(centerX, centerY - h * 0.22);
    }

    if (this.devText) this.devText.setPosition(centerX, centerY).setFontSize(Math.round(45 * uiScale));
    if (this.skipHint) this.skipHint.setPosition(centerX, h - Math.max(24, h * 0.05)).setFontSize(Math.round(12 * uiScale));
    if (this.breathOverlay) this.breathOverlay.setPosition(centerX, centerY).setSize(w, h);

    this.narrativeTexts.forEach(t => {
      t.setPosition(centerX, centerY).setFontSize(Math.round(40 * uiScale));
    });

    const despairIdx = this.narrativeTexts.length - 2;
    const gap = Math.max(20, h * 0.08);
    if (this.narrativeTexts[despairIdx]) this.narrativeTexts[despairIdx].y = centerY - gap / 2;
    if (this.narrativeTexts[despairIdx + 1]) this.narrativeTexts[despairIdx + 1].y = centerY + gap / 2;

    if (this.fireEmitter) {
      this.fireEmitter.setPosition(centerX, this.dragon ? (this.dragon.y + this.dragon.displayHeight * 0.12) : h * 0.35);
    }
  }

  private startSequence(n1: any, n2: any, n3: any, nD: any, nV: any) {
    this.tweens.chain({
      tweens: [
        { targets: this.devText, alpha: 1, duration: 2500, ease: 'Power2' },
        { targets: this.devText, alpha: 1, duration: 2000, onStart: () => this.cameras.main.shake(6000, 0.005) },
        { targets: this.devText, alpha: 0, duration: 2000, ease: 'Power2' },
        { targets: this.bgs[0], alpha: 1, duration: 1500, ease: 'Linear' },
        {
          targets: this.dragon, alpha: { from: 0, to: 1 }, duration: 3000, ease: 'Sine.easeInOut', hold: 500,
          onStart: () => { this.dragon!.setVisible(true); this.cameras.main.shake(3500, 0.005); }
        },
        { targets: this.dragon, y: '-=150', scale: '*=0.7', duration: 1000, ease: 'Quad.easeOut' },
        {
            targets: this.breathOverlay, alpha: 0.8, duration: 2500, yoyo: true, hold: 100,
            onStart: () => { this.fireEmitter!.start(); this.cameras.main.shake(2500, 0.03); },
            onComplete: () => { this.fireEmitter!.stop(); this.dragon!.setVisible(false); }
        },
        { targets: this.bgs[1], alpha: 1, duration: 2000, hold: 2500, ease: 'Linear' },
        { targets: n1, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n1, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[2], alpha: 1, duration: 2000, hold: 2500, ease: 'Linear' },
        { targets: n2, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n2, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[3], alpha: 1, duration: 3000, hold: 3500, ease: 'Linear' },
        { targets: n3, alpha: 1, duration: 1000, hold: 3000, ease: 'Power2' },
        { targets: n3, alpha: 0, duration: 1000, ease: 'Power2' },
        { targets: this.bgs[4], alpha: 1, duration: 3000, ease: 'Linear' },
        { targets: nD, alpha: 1, duration: 2000, ease: 'Power2', delay: 500 },
        { targets: nV, alpha: 1, duration: 2500, ease: 'Power2' },
        {
          targets: [...this.bgs, nD, nV], alpha: 0, duration: 3000, delay: 3000,
          onComplete: () => { this.game.events.emit('intro-complete'); }
        }
      ]
    });
  }
}

import Phaser from 'phaser';

export interface MainForgeData {
  hasFurnace: boolean;
  onInteract: (type: 'ANVIL' | 'FURNACE' | 'EMPTY_SLOT') => void;
}

export default class MainForgeScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;

  private onInteract?: (type: 'ANVIL' | 'FURNACE' | 'EMPTY_SLOT') => void;
  private hasFurnace: boolean = false;
  private floor?: Phaser.GameObjects.Rectangle;
  private bg?: Phaser.GameObjects.Rectangle;
  private glow?: Phaser.GameObjects.Arc;
  private anvilContainer?: Phaser.GameObjects.Container;
  private anvilText?: Phaser.GameObjects.Text;
  private furnaceObj?: any;

  private root!: Phaser.GameObjects.Container;

  constructor() {
    super('MainForgeScene');
  }

  init(data: MainForgeData) {
    this.hasFurnace = data.hasFurnace;
    this.onInteract = data.onInteract;
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);

    this.bg = this.add.rectangle(0, 0, 0, 0, 0x1c1917);
    this.root.add(this.bg);

    this.floor = this.add.rectangle(0, 0, 0, 0, 0x292524);
    this.root.add(this.floor);

    this.glow = this.add.circle(0, 0, 200, 0x000000, 0.5);
    this.root.add(this.glow);

    this.createAnvil();
    this.createFurnaceSlot();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.gameSize.width;
    const h = gameSize?.height ?? this.scale.gameSize.height;
    const centerX = w / 2;
    const centerY = h / 2;
    const isCompact = h < 450;

    if (this.bg) this.bg.setPosition(centerX, centerY).setSize(w, h);
    if (this.floor) this.floor.setPosition(centerX, centerY - (h * 0.1)).setSize(w, h * 0.6);
    if (this.glow) this.glow.setPosition(centerX, centerY - (h * 0.2)).setRadius(h * 0.4);

    if (this.anvilContainer) {
        this.anvilContainer.setPosition(centerX - (w * 0.2), centerY + (h * 0.1));
        if (this.anvilText) this.anvilText.setPosition(this.anvilContainer.x, this.anvilContainer.y + (isCompact ? 50 : 70));
    }

    if (this.furnaceObj) {
        const fx = centerX + (w * 0.2);
        const fy = centerY + (h * 0.05);
        if (this.furnaceObj.body) this.furnaceObj.body.setPosition(fx, fy);
        if (this.furnaceObj.fire) this.furnaceObj.fire.setPosition(fx, fy + 20);
        if (this.furnaceObj.text) this.furnaceObj.text.setPosition(fx, fy + (this.hasFurnace ? -80 : 0));
        if (this.furnaceObj.outline) this.furnaceObj.outline.setPosition(fx, fy);
    }
  }

  private createAnvil() {
    this.anvilContainer = this.add.container(0, 0);
    const base = this.add.rectangle(0, 40, 80, 40, 0x44403c).setStrokeStyle(2, 0x000000);
    const top = this.add.rectangle(0, 0, 100, 30, 0x57534e).setStrokeStyle(2, 0x000000);
    const horn = this.add.triangle(-60, 0, 0, 0, 20, 30, 0, 30, 0x57534e).setStrokeStyle(2, 0x000000);
    this.anvilContainer.add([base, horn, top]).setSize(120, 100);
    this.anvilContainer.setInteractive(new Phaser.Geom.Rectangle(-60, -20, 120, 100), Phaser.Geom.Rectangle.Contains);
    this.anvilContainer.on('pointerdown', () => {
      this.tweens.add({ targets: this.anvilContainer, scale: 0.95, yoyo: true, duration: 50 });
      this.onInteract?.('ANVIL');
    });
    this.anvilText = this.add.text(0, 0, 'ANVIL', { fontFamily: 'monospace', fontSize: '12px', color: '#78716c' }).setOrigin(0.5);
    this.root.add([this.anvilContainer, this.anvilText]);
  }

  private createFurnaceSlot() {
    this.furnaceObj = {};
    if (this.hasFurnace) {
      this.furnaceObj.body = this.add.rectangle(0, 0, 100, 140, 0x44403c).setStrokeStyle(2, 0x000000);
      this.furnaceObj.fire = this.add.circle(0, 0, 30, 0xea580c);
      this.tweens.add({ targets: this.furnaceObj.fire, alpha: 0.6, scale: 1.1, yoyo: true, repeat: -1, duration: 800, ease: 'Sine.easeInOut' });
      this.furnaceObj.body.setInteractive().on('pointerdown', () => this.onInteract?.('FURNACE'));
      this.furnaceObj.text = this.add.text(0, 0, 'FURNACE', { fontFamily: 'monospace', fontSize: '12px', color: '#ea580c' }).setOrigin(0.5);
      this.root.add([this.furnaceObj.body, this.furnaceObj.fire, this.furnaceObj.text]);
    } else {
      this.furnaceObj.outline = this.add.rectangle(0, 0, 100, 140).setStrokeStyle(2, 0x44403c, 1);
      this.furnaceObj.text = this.add.text(0, 0, 'EMPTY SLOT', { fontSize: '10px', color: '#44403c' }).setOrigin(0.5);
      this.furnaceObj.outline.setInteractive().on('pointerdown', () => this.onInteract?.('EMPTY_SLOT'));
      this.root.add([this.furnaceObj.outline, this.furnaceObj.text]);
    }
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  public load!: Phaser.Loader.LoaderPlugin;
  public add!: Phaser.GameObjects.GameObjectFactory;
  public make!: Phaser.GameObjects.GameObjectCreator;
  public tweens!: Phaser.Tweens.TweenManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public anims!: Phaser.Animations.AnimationManager;
  public time!: Phaser.Time.Clock;
  public textures!: Phaser.Textures.TextureManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45, 
  };

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;

  private lastPumpTime: number = 0;
  private pumpCooldown: number = 100; 

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = (20 + (this.temperature / 100) * 1480) > 400;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.lastPumpTime = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;

    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(pointer.x, pointer.y); return; }

      if (this.isPointerInHitArea(pointer.x, pointer.y) || Phaser.Math.Distance.Between(pointer.x, pointer.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(pointer.x, pointer.y);
      } else {
          this.handleMiss(pointer.x, pointer.y);
      }
    }, this);
  }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
    } else {
        this.cameras.main.shake(50, 0.005);
        this.highlightHeatUpBtn();
    }
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished) return;
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
        this.highlightHeatUpBtn();
        return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff);
      this.combo++;
      this.perfectCount++;
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
      }
      this.createSparks(30, 0xffaa00, 1.5, 'spark_perfect', vx, vy); 
      this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff);
      this.combo = 0;
      this.perfectCount = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', vx, vy);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else {
      this.handleMiss(vx, vy);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private isBellowsClick(objs: any[]) { 
    return objs.includes(this.bellowsContainer) || (this.bellowsContainer && this.bellowsContainer.list.some(c => objs.includes(c))); 
  }
  private isHeatUpClick(objs: any[]) { 
    return objs.includes(this.heatUpBtnContainer) || (this.heatUpBtnContainer && this.heatUpBtnContainer.list.some(c => objs.includes(c))); 
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -10, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', { fontFamily: 'monospace', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.gameSize.width;
    const h = gameSize?.height ?? this.scale.gameSize.height;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isCompact = h < 450;

    if (this.backgroundTile) this.backgroundTile.setSize(w, h);
    if (this.bgOverlay) this.bgOverlay.setSize(w, h);
    if (this.flashOverlay) this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : this.anvilConfig.yOffset);
    this.startRadius = Phaser.Math.Clamp(h * 0.35, 120, 240);
    this.targetRadius = this.startRadius * 0.25;

    if (this.anvilImage) {
      const targetWidth = w * (isCompact ? 1.2 : 1.4);
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, anvilY + this.anvilConfig.imageOffsetY);
    }
    if (this.ambientGlow) this.ambientGlow.setPosition(this.centerX, anvilY);

    const surfaceH = h * this.anvilConfig.heightRatio;
    const bladeY = anvilY - surfaceH * 0.4; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 60;
    this.bladeContainer.y += Math.sin(rad) * 60;

    this.hammerHitArea.setPosition(this.bladeContainer.x - Math.sin(rad) * this.anvilConfig.hitAreaOffset, this.bladeContainer.y + Math.cos(rad) * this.anvilConfig.hitAreaOffset);
    this.rebuildHitPoly();
    this.repositionUIElements(w, h, isCompact);
    if (this.isPlaying) this.resetRing(); 
  }

  private repositionUIElements(w: number, h: number, isCompact: boolean) {
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, 55).setFontSize(isCompact ? '14px' : '16px');

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100; 
    const barH = isCompact ? 120 : 200;

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    tFrame.setPosition(sideX, sideY).setSize(28, barH + 10);
    tBg.setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20).setFontSize(isCompact ? '12px' : '14px');

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45).setScale(isCompact ? 0.8 : 1);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap).setScale(isCompact ? 0.8 : 1);

    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180)).setFontSize(isCompact ? '18px' : '24px');
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.perfectCount = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x ?? this.hitX, y ?? this.hitY);
    this.updateProgressBar();
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    if (this.isPlaying) {
      if (this.temperature <= 0) {
        this.targetRing.clear(); this.approachRing.clear();
        this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
      } else {
        if (this.infoText.visible && (this.infoText.text.includes('COLD') || this.infoText.text.includes('FUEL'))) {
            this.infoText.setVisible(false); this.resetRing();
        }
        this.handleRingLogic(delta);
      }
    }
    this.refreshVisuals();
    if (!this.isPlaying) {
        const realTemp = 20 + (this.temperature / 100) * 1480;
        if (this.isReadyToStart && realTemp <= 400) {
            this.isReadyToStart = false;
            this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6').setVisible(true);
        } else if (!this.isReadyToStart && realTemp > 400) {
            this.isReadyToStart = true;
            this.infoText.setText('TOUCH TO START').setColor('#fbbf24').setVisible(true);
        }
    }
  }

  private refreshVisuals() {
    if (this.perfectCount > 0) {
        this.qualityText.setVisible(false);
    } else {
        this.qualityText.setVisible(true);
        this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    }

    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    const realTemp = Math.floor(20 + ratio * 1480);
    this.tempValueText.setText(`${realTemp}°C`);

    let color: number;
    if (ratio < 0.20) {
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 59, g: 130, b: 246 }), 
            Phaser.Display.Color.ObjectToColor({ r: 28, g: 25, b: 23 }), 100, (ratio / 0.20) * 100
        ).color;
    } else if (ratio < 0.45) {
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 28, g: 25, b: 23 }),
            Phaser.Display.Color.ObjectToColor({ r: 127, g: 29, b: 29 }), 100, ((ratio - 0.20) / 0.25) * 100
        ).color;
    } else if (ratio < 0.75) {
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 127, g: 29, b: 29 }),
            Phaser.Display.Color.ObjectToColor({ r: 249, g: 115, b: 22 }), 100, ((ratio - 0.45) / 0.30) * 100
        ).color;
    } else {
        color = Phaser.Display.Color.Interpolate.ColorWithColor(
            Phaser.Display.Color.ObjectToColor({ r: 249, g: 115, b: 22 }),
            Phaser.Display.Color.ObjectToColor({ r: 255, g: 253, b: 235 }), 100, ((ratio - 0.75) / 0.25) * 100
        ).color;
    }
    this.tempBar.setFillStyle(color);

    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    this.setBladeStage(stage);
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);

    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
          this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
          this.bladeContainer.add(this.bladeImage);
      } else if (this.bladeImage.texture.key !== key) {
          this.bladeImage.setTexture(key);
          this.tweens.add({ targets: this.bladeContainer, scale: 1.1, duration: 100, yoyo: true });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 25) {
        this.combo = 0; this.perfectCount = 0; this.resetRing();
    }
  }

  private resetRing() {
    this.targetRing.clear(); this.approachRing.clear();
    if (this.temperature <= 0) return;
    this.currentRadius = this.startRadius;
    this.ringTimer = 0;
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35); const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
        this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color });
    this.root.add(emitter); emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Arial Black', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { 
        this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); 
        this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700 }); 
    }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg); this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, `${this.getQualityLabel(this.currentQuality)} CRAFT!`, { fontFamily: 'Georgia', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  private highlightHeatUpBtn() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    if (!bg) return;
    this.tweens.killTweensOf(this.heatUpBtnContainer);
    this.tweens.add({ targets: this.heatUpBtnContainer, scale: 1.2, duration: 200, yoyo: true, ease: 'Cubic.easeOut', onStart: () => { bg.setStrokeStyle(4, 0xffaa00); }, onComplete: () => { this.refreshHeatUpButton(); } });
  }

  private pumpBellows() {
    if (this.time.now - this.lastPumpTime < this.pumpCooldown) return;
    this.lastPumpTime = this.time.now;
    if (this.bellowsSprite) this.bellowsSprite.play('bellows_pump', true);
    const realTemp = 20 + (this.temperature / 100) * 1480;
    if (realTemp <= 400) { this.highlightHeatUpBtn(); return; }
    if (this.temperature >= 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (this.temperature > 0 && !this.isPlaying && !this.isReadyToStart) {
          if (20 + (this.temperature / 100) * 1480 > 400) {
              this.isReadyToStart = true;
              this.infoText.setText('TOUCH TO START').setColor('#fbbf24').setVisible(true);
          }
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0 && this.onHeatUpRequest) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      this.onHeatUpRequest();
    } else { this.cameras.main.shake(100, 0.005); }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying && 20 + (this.temperature / 100) * 1480 > 400) {
        this.isReadyToStart = true;
        this.infoText.setText('TOUCH TO START').setColor('#fbbf24').setVisible(true);
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; this.refreshHeatUpButton(); }

  private refreshHeatUpButton() {
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`);
    if (bg) bg.setStrokeStyle(3, this.charcoalCount > 0 ? 0xea580c : 0x292524);
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';

export interface MainForgeData {
  hasFurnace: boolean;
  onInteract: (type: 'ANVIL' | 'FURNACE' | 'EMPTY_SLOT') => void;
}

export default class MainForgeScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;

  private onInteract?: (type: 'ANVIL' | 'FURNACE' | 'EMPTY_SLOT') => void;
  private hasFurnace: boolean = false;
  private floor?: Phaser.GameObjects.Rectangle;
  private bg?: Phaser.GameObjects.Rectangle;
  private glow?: Phaser.GameObjects.Arc;
  private anvilContainer?: Phaser.GameObjects.Container;
  private anvilText?: Phaser.GameObjects.Text;
  private furnaceObj?: any;

  private root!: Phaser.GameObjects.Container;

  constructor() {
    super('MainForgeScene');
  }

  init(data: MainForgeData) {
    this.hasFurnace = data.hasFurnace;
    this.onInteract = data.onInteract;
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);

    this.bg = this.add.rectangle(0, 0, 0, 0, 0x1c1917);
    this.root.add(this.bg);

    this.floor = this.add.rectangle(0, 0, 0, 0, 0x292524);
    this.root.add(this.floor);

    this.glow = this.add.circle(0, 0, 200, 0x000000, 0.5);
    this.root.add(this.glow);

    this.createAnvil();
    this.createFurnaceSlot();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.gameSize.width;
    const h = gameSize?.height ?? this.scale.gameSize.height;
    const centerX = w / 2;
    const centerY = h / 2;
    const isCompact = h < 450;

    if (this.bg) this.bg.setPosition(centerX, centerY).setSize(w, h);
    if (this.floor) this.floor.setPosition(centerX, centerY - (h * 0.1)).setSize(w, h * 0.6);
    if (this.glow) this.glow.setPosition(centerX, centerY - (h * 0.2)).setRadius(h * 0.4);

    if (this.anvilContainer) {
        this.anvilContainer.setPosition(centerX - (w * 0.2), centerY + (h * 0.1));
        if (this.anvilText) this.anvilText.setPosition(this.anvilContainer.x, this.anvilContainer.y + (isCompact ? 50 : 70));
    }

    if (this.furnaceObj) {
        const fx = centerX + (w * 0.2);
        const fy = centerY + (h * 0.05);
        if (this.furnaceObj.body) this.furnaceObj.body.setPosition(fx, fy);
        if (this.furnaceObj.fire) this.furnaceObj.fire.setPosition(fx, fy + 20);
        if (this.furnaceObj.text) this.furnaceObj.text.setPosition(fx, fy + (this.hasFurnace ? -80 : 0));
        if (this.furnaceObj.outline) this.furnaceObj.outline.setPosition(fx, fy);
    }
  }

  private createAnvil() {
    this.anvilContainer = this.add.container(0, 0);
    const base = this.add.rectangle(0, 40, 80, 40, 0x44403c).setStrokeStyle(2, 0x000000);
    const top = this.add.rectangle(0, 0, 100, 30, 0x57534e).setStrokeStyle(2, 0x000000);
    const horn = this.add.triangle(-60, 0, 0, 0, 20, 30, 0, 30, 0x57534e).setStrokeStyle(2, 0x000000);
    this.anvilContainer.add([base, horn, top]).setSize(120, 100);
    this.anvilContainer.setInteractive(new Phaser.Geom.Rectangle(-60, -20, 120, 100), Phaser.Geom.Rectangle.Contains);
    this.anvilContainer.on('pointerdown', () => {
      this.tweens.add({ targets: this.anvilContainer, scale: 0.95, yoyo: true, duration: 50 });
      this.onInteract?.('ANVIL');
    });
    this.anvilText = this.add.text(0, 0, 'ANVIL', { fontFamily: 'monospace', fontSize: '12px', color: '#78716c' }).setOrigin(0.5);
    this.root.add([this.anvilContainer, this.anvilText]);
  }

  private createFurnaceSlot() {
    this.furnaceObj = {};
    if (this.hasFurnace) {
      this.furnaceObj.body = this.add.rectangle(0, 0, 100, 140, 0x44403c).setStrokeStyle(2, 0x000000);
      this.furnaceObj.fire = this.add.circle(0, 0, 30, 0xea580c);
      this.tweens.add({ targets: this.furnaceObj.fire, alpha: 0.6, scale: 1.1, yoyo: true, repeat: -1, duration: 800, ease: 'Sine.easeInOut' });
      this.furnaceObj.body.setInteractive().on('pointerdown', () => this.onInteract?.('FURNACE'));
      this.furnaceObj.text = this.add.text(0, 0, 'FURNACE', { fontFamily: 'monospace', fontSize: '12px', color: '#ea580c' }).setOrigin(0.5);
      this.root.add([this.furnaceObj.body, this.furnaceObj.fire, this.furnaceObj.text]);
    } else {
      this.furnaceObj.outline = this.add.rectangle(0, 0, 100, 140).setStrokeStyle(2, 0x44403c, 1);
      this.furnaceObj.text = this.add.text(0, 0, 'EMPTY SLOT', { fontSize: '10px', color: '#44403c' }).setOrigin(0.5);
      this.furnaceObj.outline.setInteractive().on('pointerdown', () => this.onInteract?.('EMPTY_SLOT'));
      this.root.add([this.furnaceObj.outline, this.furnaceObj.text]);
    }
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeImage?: Phaser.GameObjects.Image;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;
  private temperature: number = 0;
  private coolingRate: number = 2;
  private charcoalCount: number = 0;

  private startRadius: number = 180;
  private targetRadius: number = 45;
  private currentRadius: number = 180;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;

  private lastPumpTime: number = 0;
  private pumpCooldown: number = 100; 

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;
  private virtualW = 0;
  private virtualH = 0;
  private isPortrait = false;

  constructor() {
    super('SmithingScene');
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = (20 + (this.temperature / 100) * 1480) > 400;
    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  private toVirtual(sx: number, sy: number) {
    if (!this.isPortrait) return { x: sx, y: sy };
    return { x: sy, y: this.virtualH - sx };
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      const virtual = this.toVirtual(pointer.x, pointer.y);
      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(virtual.x, virtual.y); return; }
      if (this.isPointerInHitArea(virtual.x, virtual.y) || Phaser.Math.Distance.Between(virtual.x, virtual.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(virtual.x, virtual.y);
      } else {
          this.handleMiss(virtual.x, virtual.y);
      }
    }, this);
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar, this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnLabel = this.add.text(0, 0, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 15, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, 'TOUCH TO START', { fontFamily: 'monospace', fontSize: '24px', color: '#fbbf24', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
  }

  private handleResize(gameSize: Phaser.Structs.Size) {
    const screenW = gameSize.width;
    const screenH = gameSize.height;
    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    const w = this.virtualW;
    const h = this.virtualH;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isCompact = h < 450;

    this.backgroundTile.setSize(w, h);
    this.bgOverlay.setSize(w, h);
    this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : 20);
    this.anvilImage.setPosition(this.centerX, anvilY + 20).setScale((w * (isCompact ? 1.2 : 1.4)) / this.anvilImage.width);
    this.ambientGlow.setPosition(this.centerX, anvilY);
    this.bladeContainer.setPosition(this.centerX, anvilY - h * 0.4 * 0.4);
    this.hammerHitArea.setPosition(this.bladeContainer.x, this.bladeContainer.y + 45);
    this.rebuildHitPoly();
    this.repositionUI(w, h, isCompact);
  }

  private repositionUI(w: number, h: number, isCompact: boolean) {
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.qualityText.setPosition(this.centerX, 55);

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100;
    const barH = isCompact ? 120 : 200;
    (this.uiContainer.getByName('tempFrame') as any).setPosition(sideX, sideY).setSize(28, barH + 10);
    (this.uiContainer.getByName('tempBg') as any).setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20);

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap);
    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180));
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }
  private isBellowsClick(objs: any[]) { return objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c)); }
  private isHeatUpClick(objs: any[]) { return objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c)); }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true; this.infoText.setVisible(false); this.resetRing();
    } else {
        this.cameras.main.shake(50, 0.005); this.highlightHeatUpBtn();
    }
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished || this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    if (this.temperature <= 15) { this.highlightHeatUpBtn(); return; }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    if (diff < this.targetRadius * 0.35) {
      this.score += 8; this.combo++; this.perfectCount++;
      if (this.perfectCount >= 6) this.currentQuality += 1;
      this.showFeedback('PERFECT!', 0xffb300, 1.4, vx, vy);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += 5; this.combo = 0; this.perfectCount = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, vx, vy);
    } else {
      this.handleMiss(vx, vy);
    }
    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private handleMiss(x: number, y: number) {
    this.score = Math.max(0, this.score - 5); this.combo = 0; this.perfectCount = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x, y);
    this.updateProgressBar(); this.resetRing();
  }

  private resetRing() {
    this.targetRing.clear(); this.approachRing.clear();
    if (this.temperature <= 0) return;
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35); const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) this.targetRing.fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'monospace', fontSize: '24px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: { from: 1, to: 0 }, duration: 800, onComplete: () => fb.destroy() });
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    if (this.isPlaying && this.temperature > 0) {
      this.ringTimer += delta;
      const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
      this.currentRadius = this.startRadius * (1 - t * t);
      this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
      if (this.currentRadius < this.targetRadius - 25) this.handleMiss(this.hitX, this.hitY);
    }
    this.refreshVisuals();
  }

  private refreshVisuals() {
    this.qualityText.setVisible(this.perfectCount === 0);
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    this.ambientGlow.setAlpha(ratio * 0.4);
  }

  private highlightHeatUpBtn() {
    this.tweens.add({ targets: this.heatUpBtnContainer, scale: 1.2, duration: 200, yoyo: true });
  }

  private pumpBellows() {
    if (this.time.now - this.lastPumpTime < this.pumpCooldown) return;
    this.lastPumpTime = this.time.now;
    if (this.bellowsSprite) this.bellowsSprite.play('bellows_pump', true);
    this.temperature = Math.min(100, this.temperature + 5);
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    this.flashOverlay.setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400 });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; (this.heatUpBtnContainer.getByName('countTxt') as any).setText(`x${count}`); }
  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';

export interface MainForgeData {
  hasFurnace: boolean;
  onInteract: (type: 'ANVIL' | 'FURNACE' | 'EMPTY_SLOT') => void;
}

export default class MainForgeScene extends Phaser.Scene {
  private onInteract?: (type: 'ANVIL' | 'FURNACE' | 'EMPTY_SLOT') => void;
  private hasFurnace: boolean = false;
  private floor?: Phaser.GameObjects.Rectangle;
  private bg?: Phaser.GameObjects.Rectangle;
  private glow?: Phaser.GameObjects.Arc;
  private anvilContainer?: Phaser.GameObjects.Container;
  private anvilText?: Phaser.GameObjects.Text;
  private furnaceObj?: any;

  private root!: Phaser.GameObjects.Container;
  private virtualW = 0;
  private virtualH = 0;
  private isPortrait = false;

  constructor() {
    super('MainForgeScene');
  }

  init(data: MainForgeData) {
    this.hasFurnace = data.hasFurnace;
    this.onInteract = data.onInteract;
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);

    this.bg = this.add.rectangle(0, 0, 0, 0, 0x1c1917);
    this.root.add(this.bg);

    this.floor = this.add.rectangle(0, 0, 0, 0, 0x292524);
    this.root.add(this.floor);

    this.glow = this.add.circle(0, 0, 200, 0x000000, 0.5);
    this.root.add(this.glow);

    this.createAnvil();
    this.createFurnaceSlot();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
  }

  private handleResize(gameSize: Phaser.Structs.Size) {
    const screenW = gameSize.width;
    const screenH = gameSize.height;
    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    const w = this.virtualW;
    const h = this.virtualH;
    const centerX = w / 2;
    const centerY = h / 2;
    const isCompact = h < 450;

    if (this.bg) this.bg.setPosition(centerX, centerY).setSize(w, h);
    if (this.floor) this.floor.setPosition(centerX, centerY - (h * 0.1)).setSize(w, h * 0.6);
    if (this.glow) this.glow.setPosition(centerX, centerY - (h * 0.2)).setRadius(h * 0.4);

    if (this.anvilContainer) {
        this.anvilContainer.setPosition(centerX - (w * 0.2), centerY + (h * 0.1));
        if (this.anvilText) this.anvilText.setPosition(this.anvilContainer.x, this.anvilContainer.y + (isCompact ? 50 : 70));
    }

    if (this.furnaceObj) {
        const fx = centerX + (w * 0.2);
        const fy = centerY + (h * 0.05);
        if (this.furnaceObj.body) this.furnaceObj.body.setPosition(fx, fy);
        if (this.furnaceObj.fire) this.furnaceObj.fire.setPosition(fx, fy + 20);
        if (this.furnaceObj.text) this.furnaceObj.text.setPosition(fx, fy + (this.hasFurnace ? -80 : 0));
        if (this.furnaceObj.outline) this.furnaceObj.outline.setPosition(fx, fy);
    }
  }

  private createAnvil() {
    this.anvilContainer = this.add.container(0, 0);
    const base = this.add.rectangle(0, 40, 80, 40, 0x44403c).setStrokeStyle(2, 0x000000);
    const top = this.add.rectangle(0, 0, 100, 30, 0x57534e).setStrokeStyle(2, 0x000000);
    const horn = this.add.triangle(-60, 0, 0, 0, 20, 30, 0, 30, 0x57534e).setStrokeStyle(2, 0x000000);
    this.anvilContainer.add([base, horn, top]).setSize(120, 100).setInteractive(new Phaser.Geom.Rectangle(-60, -20, 120, 100), Phaser.Geom.Rectangle.Contains);
    this.anvilContainer.on('pointerdown', () => this.onInteract?.('ANVIL'));
    this.anvilText = this.add.text(0, 0, 'ANVIL', { fontFamily: 'monospace', fontSize: '12px', color: '#78716c' }).setOrigin(0.5);
    this.root.add([this.anvilContainer, this.anvilText]);
  }

  private createFurnaceSlot() {
    this.furnaceObj = {};
    if (this.hasFurnace) {
      this.furnaceObj.body = this.add.rectangle(0, 0, 100, 140, 0x44403c).setStrokeStyle(2, 0x000000).setInteractive().on('pointerdown', () => this.onInteract?.('FURNACE'));
      this.furnaceObj.fire = this.add.circle(0, 0, 30, 0xea580c);
      this.furnaceObj.text = this.add.text(0, 0, 'FURNACE', { fontFamily: 'monospace', fontSize: '12px', color: '#ea580c' }).setOrigin(0.5);
      this.root.add([this.furnaceObj.body, this.furnaceObj.fire, this.furnaceObj.text]);
    } else {
      this.furnaceObj.outline = this.add.rectangle(0, 0, 100, 140).setStrokeStyle(2, 0x44403c, 1).setInteractive().on('pointerdown', () => this.onInteract?.('EMPTY_SLOT'));
      this.furnaceObj.text = this.add.text(0, 0, 'EMPTY SLOT', { fontSize: '10px', color: '#44403c' }).setOrigin(0.5);
      this.root.add([this.furnaceObj.outline, this.furnaceObj.text]);
    }
  }
}

