    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  private toVirtual(sx: number, sy: number) {
    if (!this.isPortrait) return { x: sx, y: sy };
    return { x: sy, y: this.virtualH - sx };
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);

    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setAlpha(0.7);
    this.root.add(this.backgroundTile);

    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0);
    this.root.add(this.bgOverlay);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5);
    this.root.add(this.anvilImage);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.root.add(this.bladeContainer);

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.root.add(this.hammerHitArea);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);

    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      const virtual = this.toVirtual(pointer.x, pointer.y);
      if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
      /* Fix: Handled the heat-up button click by calling the requestHeatUp method */
      if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
      if (!this.isPlaying) { this.handleStartTap(virtual.x, virtual.y); return; }
      if (this.isPointerInHitArea(virtual.x, virtual.y) || Phaser.Math.Distance.Between(virtual.x, virtual.y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(virtual.x, virtual.y);
      } else {
          this.handleMiss(virtual.x, virtual.y);
      }
    }, this);
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'monospace', fontSize: '16px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);

    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar, this.tempValueText
    ]);

    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.3);
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-50, -40, 100, 80), Phaser.Geom.Rectangle.Contains);

    this.heatUpBtnContainer = this.add.container(0, 0);
    const btnBg = this.add.rectangle(0, 0, 80, 60, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnLabel = this.add.text(0, 0, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 15, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Rectangle(-40, -30, 80, 60), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, 'TOUCH TO START', { fontFamily: 'monospace', fontSize: '24px', color: '#fbbf24', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
  }

  private handleResize(gameSize: Phaser.Structs.Size) {
    const screenW = gameSize.width;
    const screenH = gameSize.height;
    this.isPortrait = screenH > screenW;
    this.virtualW = this.isPortrait ? screenH : screenW;
    this.virtualH = this.isPortrait ? screenW : screenH;

    if (this.isPortrait) {
      this.root.setRotation(Math.PI / 2);
      this.root.setPosition(this.virtualH, 0);
    } else {
      this.root.setRotation(0);
      this.root.setPosition(0, 0);
    }

    const w = this.virtualW;
    const h = this.virtualH;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isCompact = h < 450;

    this.backgroundTile.setSize(w, h);
    this.bgOverlay.setSize(w, h);
    this.flashOverlay.setSize(w, h);

    const anvilY = this.centerY + (isCompact ? 20 : 20);
    this.anvilImage.setPosition(this.centerX, anvilY + 20).setScale((w * (isCompact ? 1.2 : 1.4)) / this.anvilImage.width);
    this.ambientGlow.setPosition(this.centerX, anvilY);
    this.bladeContainer.setPosition(this.centerX, anvilY - h * 0.4 * 0.4);
    this.hammerHitArea.setPosition(this.bladeContainer.x, this.bladeContainer.y + 45);
    this.rebuildHitPoly();
    this.repositionUI(w, h, isCompact);
  }

  private repositionUI(w: number, h: number, isCompact: boolean) {
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(w * 0.6, 300);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, 25).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, 25);
    this.qualityText.setPosition(this.centerX, 55);

    const sideX = w - (isCompact ? 40 : 60);
    const sideY = isCompact ? h * 0.3 : this.centerY - 100;
    const barH = isCompact ? 120 : 200;
    (this.uiContainer.getByName('tempFrame') as any).setPosition(sideX, sideY).setSize(28, barH + 10);
    (this.uiContainer.getByName('tempBg') as any).setPosition(sideX, sideY).setSize(22, barH);
    this.tempBar.setPosition(sideX, sideY + barH/2).setSize(16, barH);
    this.tempValueText.setPosition(sideX, sideY - barH/2 - 20);

    const ctrlGap = isCompact ? 65 : 85;
    this.bellowsContainer.setPosition(sideX, sideY + barH/2 + 45);
    this.heatUpBtnContainer.setPosition(sideX, sideY + barH/2 + 45 + ctrlGap);
    this.infoText.setPosition(this.centerX, this.centerY - (isCompact ? 100 : 180));
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [{ x: -w/2, y: -h/2 }, { x: w/2, y: -h/2 }, { x: w/2, y: h/2 }, { x: -w/2, y: h/2 }].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }
  private isBellowsClick(objs: any[]) { return objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c)); }
  private isHeatUpClick(objs: any[]) { return objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c)); }

  private handleStartTap(vx: number, vy: number) {
    if (this.isReadyToStart) {
        this.isPlaying = true; this.infoText.setVisible(false); this.resetRing();
    } else {
        this.cameras.main.shake(50, 0.005); this.highlightHeatUpBtn();
    }
  }

  /* Fix: Added requestHeatUp method to handle charcoal usage requests by calling the respective callback */
  private requestHeatUp() {
    if (this.charcoalCount > 0) {
      this.onHeatUpRequest?.();
    } else {
      this.cameras.main.shake(100, 0.005);
    }
  }

  /* Fix: Added winGame method to gracefully end the minigame and return the final quality result to the context */
  private winGame() {
    if (this.isFinished) return;
    this.isFinished = true;
    this.isPlaying = false;
    this.onStatusUpdate?.(this.temperature);
    this.onComplete?.(this.currentQuality);
  }

  private handleHammerSwing(vx: number, vy: number) {
    if (this.isFinished || this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    if (this.temperature <= 15) { this.highlightHeatUpBtn(); return; }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    if (diff < this.targetRadius * 0.35) {
      this.score += 8; this.combo++; this.perfectCount++;
      if (this.perfectCount >= 6) this.currentQuality += 1;
      this.showFeedback('PERFECT!', 0xffb300, 1.4, vx, vy);
      this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += 5; this.combo = 0; this.perfectCount = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, 1.1, vx, vy);
    } else {
      this.handleMiss(vx, vy);
    }
    this.updateProgressBar();
    /* Fix: Successfully triggers winGame when target progress score is reached */
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private handleMiss(x: number, y: number) {
    this.score = Math.max(0, this.score - 5); this.combo = 0; this.perfectCount = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(100, 0.01);
    this.showFeedback('MISS', 0xef4444, 1.2, x, y);
    this.updateProgressBar(); this.resetRing();
  }

  private resetRing() {
    this.targetRing.clear(); this.approachRing.clear();
    if (this.temperature <= 0) return;
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35); const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) this.targetRing.fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(4, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
  }

  private updateProgressBar() { 
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (progBg) this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'monospace', fontSize: '24px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(25);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: { from: 1, to: 0 }, duration: 800, onComplete: () => fb.destroy() });
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    if (this.isPlaying && this.temperature > 0) {
      this.ringTimer += delta;
      const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
      this.currentRadius = this.startRadius * (1 - t * t);
      this.approachRing.clear().lineStyle(6, this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24, 0.5).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
      if (this.currentRadius < this.targetRadius - 25) this.handleMiss(this.hitX, this.hitY);
    }
    this.refreshVisuals();
  }

  private refreshVisuals() {
    this.qualityText.setVisible(this.perfectCount === 0);
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    this.ambientGlow.setAlpha(ratio * 0.4);
    /* Fix: Periodically report current temperature to parent for accurate state updates */
    this.onStatusUpdate?.(this.temperature);
  }

  private highlightHeatUpBtn() {
    this.tweens.add({ targets: this.heatUpBtnContainer, scale: 1.2, duration: 200, yoyo: true });
  }

  private pumpBellows() {
    if (this.time.now - this.lastPumpTime < this.pumpCooldown) return;
    this.lastPumpTime = this.time.now;
    if (this.bellowsSprite) this.bellowsSprite.play('bellows_pump', true);
    this.temperature = Math.min(100, this.temperature + 5);
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    this.flashOverlay.setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400 });
  }

  public updateCharcoalCount(count: number) { this.charcoalCount = count; (this.heatUpBtnContainer.getByName('countTxt') as any).setText(`x${count}`); }
  public getTemperature() { return this.temperature; }
}

